check("audio subsystem play handle can cancel a pending request", () => {
  const audio = new AudioSubsystem();
  const handle = audio.play("music-loop", { volume: 0.25, loop: true, pitch: 1.5 });

  assert.equal(handle.clipId, "music-loop");
  assert.equal(handle.volume, 0.25);
  assert.equal(handle.pitch, 1.5);

  handle.setVolume(0.5);
  handle.setPitch(0.75);
  assert.equal(handle.volume, 0.5);
  assert.equal(handle.pitch, 0.75);

  handle.stop();
  audio.update({ deltaSeconds: 0.016, elapsedSeconds: 0.016, frame: 1 });

  assert.equal(handle.stopped, true);
  assert.deepEqual(audio.playedRequests(), []);
});

check("audio subsystem keeps headless looping playback alive until stopped", () => {
  const audio = new AudioSubsystem();
  const handle = audio.play("music-loop", { volume: 0.4, loop: true });

  audio.update({ deltaSeconds: 0.016, elapsedSeconds: 0.016, frame: 1 });

  assert.equal(handle.stopped, false);
  assert.deepEqual(audio.playedRequests(), [{ clipId: "music-loop", volume: 0.4, loop: true }]);

  handle.stop(0.25);
  assert.equal(handle.stopped, true);
});

check("audio subsystem finishes headless non-loop playback after update", () => {
  const audio = new AudioSubsystem();
  const handle = audio.play("ui-click", { volume: 0.7 });

  audio.update({ deltaSeconds: 0.016, elapsedSeconds: 0.016, frame: 1 });

  assert.equal(handle.stopped, true);
  assert.deepEqual(audio.playedRequests(), [{ clipId: "ui-click", volume: 0.7 }]);
});

check("resolveSpatialPannerConfig defaults, clamps, and keeps max > ref", () => {
  assert.deepEqual(resolveSpatialPannerConfig({}), DEFAULT_SPATIAL_ATTENUATION);
  // Negative/zero inputs fall back to the defaults.
  assert.deepEqual(resolveSpatialPannerConfig({ refDistance: -2, rolloff: 0 }), {
    refDistance: DEFAULT_SPATIAL_ATTENUATION.refDistance,
    maxDistance: DEFAULT_SPATIAL_ATTENUATION.maxDistance,
    rolloff: DEFAULT_SPATIAL_ATTENUATION.rolloff,
  });
  // An inverted pair is corrected so the PannerNode can't go silent/NaN.
  const fixed = resolveSpatialPannerConfig({ refDistance: 30, maxDistance: 5 });
  assert.equal(fixed.refDistance, 30);
  assert.equal(fixed.maxDistance, 31);
});

check("audio subsystem records a spatial play's position; listener pose is safe headless", () => {
  const audio = new AudioSubsystem();
  // No Web Audio context exists headless; updating the listener must not throw.
  audio.setListenerPose([1, 2, 3], [0, 0, -1]);
  audio.play("footstep", { spatial: true, position: [4, 0, -2] });
  audio.update({ deltaSeconds: 0.016, elapsedSeconds: 0.016, frame: 1 });
  assert.deepEqual(audio.playedRequests(), [
    { clipId: "footstep", spatial: true, position: [4, 0, -2] },
  ]);
});

// --- Sound Cue evaluator (pure, headless) -------------------------------------
//
// A deterministic [0,1) generator: returns the queued values in order, then 0.
// Pass it as the evaluator's `rng` so random/modulator/delay picks are exact.
const seqRng = (...values: number[]): (() => number) => {
  let i = 0;
  return () => values[i++] ?? 0;
};

// Minimal cue builder: just the node/connection lists with sensible defaults.
const makeCue = (
  nodes: SoundCueAsset["nodes"],
  connections: SoundCueAsset["connections"],
  output: SoundCueAsset["output"] = {},
): SoundCueAsset => ({ schema: 1, type: "soundCue", name: "test-cue", output, nodes, connections });

check("sound cue evaluator emits a single event for source → output", () => {
  const cue = makeCue(
    [
      { id: "out", kind: "output" },
      { id: "src", kind: "source", clipId: "clipA", volume: 0.5, pitch: 1.2 },
    ],
    [{ from: "src", to: "out" }],
  );
  assert.deepEqual(evaluateSoundCue(cue), [
    { clipId: "clipA", volume: 0.5, pitch: 1.2, loop: false, delaySeconds: 0 },
  ]);
});

check("sound cue evaluator scales by output node, then by cue.output", () => {
  // Output node volume/pitch override and multiply the source.
  const viaNode = makeCue(
    [
      { id: "out", kind: "output", volume: 0.5, pitch: 2 },
      { id: "src", kind: "source", clipId: "c" },
    ],
    [{ from: "src", to: "out" }],
  );
  assert.deepEqual(evaluateSoundCue(viaNode), [
    { clipId: "c", volume: 0.5, pitch: 2, loop: false, delaySeconds: 0 },
  ]);

  // When the output node omits volume, cue.output.volume is used as the scale.
  const viaOutput = makeCue(
    [
      { id: "out", kind: "output" },
      { id: "src", kind: "source", clipId: "c" },
    ],
    [{ from: "src", to: "out" }],
    { volume: 0.25 },
  );
  assert.equal(evaluateSoundCue(viaOutput)[0]?.volume, 0.25);
});

check("sound cue evaluator plays every mixer input simultaneously", () => {
  const cue = makeCue(
    [
      { id: "out", kind: "output" },
      { id: "mix", kind: "mixer" },
      { id: "a", kind: "source", clipId: "clipA" },
      { id: "b", kind: "source", clipId: "clipB" },
    ],
    [
      { from: "a", to: "mix" },
      { from: "b", to: "mix" },
      { from: "mix", to: "out" },
    ],
  );
  const events = evaluateSoundCue(cue);
  assert.deepEqual(
    events.map((e) => e.clipId),
    ["clipA", "clipB"],
  );
  assert.ok(events.every((e) => e.delaySeconds === 0 && e.loop === false));
});

check("sound cue evaluator random picks one input by weight and rng", () => {
  const cue = makeCue(
    [
      { id: "out", kind: "output" },
      { id: "rnd", kind: "random", weights: [3, 1] },
      { id: "a", kind: "source", clipId: "clipA" },
      { id: "b", kind: "source", clipId: "clipB" },
    ],
    [
      { from: "a", to: "rnd" },
      { from: "b", to: "rnd" },
      { from: "rnd", to: "out" },
    ],
  );
  // total weight 4: cursor < 3 → first input, else second.
  assert.deepEqual(
    evaluateSoundCue(cue, seqRng(0.7)).map((e) => e.clipId),
    ["clipA"],
  );
  assert.deepEqual(
    evaluateSoundCue(cue, seqRng(0.9)).map((e) => e.clipId),
    ["clipB"],
  );
});

check("sound cue evaluator modulator applies deterministic vol/pitch range", () => {
  const cue = makeCue(
    [
      { id: "out", kind: "output" },
      { id: "mod", kind: "modulator", volumeMin: 0.5, volumeMax: 1.5, pitchMin: 1, pitchMax: 2 },
      { id: "src", kind: "source", clipId: "c" },
    ],
    [
      { from: "src", to: "mod" },
      { from: "mod", to: "out" },
    ],
  );
  // rng 0.5 for volume → 1.0, rng 0.5 for pitch → 1.5 (consumed in that order).
  assert.deepEqual(evaluateSoundCue(cue, seqRng(0.5, 0.5)), [
    { clipId: "c", volume: 1, pitch: 1.5, loop: false, delaySeconds: 0 },
  ]);
});

check("sound cue evaluator loop node forces downstream loop", () => {
  const cue = makeCue(
    [
      { id: "out", kind: "output" },
      { id: "loop", kind: "loop" },
      { id: "src", kind: "source", clipId: "c", loop: false },
    ],
    [
      { from: "src", to: "loop" },
      { from: "loop", to: "out" },
    ],
  );
  assert.equal(evaluateSoundCue(cue)[0]?.loop, true);
});

check("sound cue evaluator source.loop is honoured without a loop node", () => {
  const cue = makeCue(
    [
      { id: "out", kind: "output" },
      { id: "src", kind: "source", clipId: "c", loop: true },
    ],
    [{ from: "src", to: "out" }],
  );
  assert.equal(evaluateSoundCue(cue)[0]?.loop, true);
});

check("sound cue evaluator delay offsets downstream events", () => {
  const cue = makeCue(
    [
      { id: "out", kind: "output" },
      { id: "delay", kind: "delay", secondsMin: 0.5, secondsMax: 0.5 },
      { id: "src", kind: "source", clipId: "c" },
    ],
    [
      { from: "src", to: "delay" },
      { from: "delay", to: "out" },
    ],
  );
  assert.equal(evaluateSoundCue(cue)[0]?.delaySeconds, 0.5);
});

check("sound cue evaluator returns nothing without an output node", () => {
  const cue = makeCue([{ id: "src", kind: "source", clipId: "c" }], []);
  assert.deepEqual(evaluateSoundCue(cue), []);
});

check("validateSoundCueGraph accepts a well-formed cue", () => {
  const cue = makeCue(
    [
      { id: "out", kind: "output" },
      { id: "src", kind: "source", clipId: "c" },
    ],
    [{ from: "src", to: "out" }],
  );
  assert.deepEqual(validateSoundCueGraph(cue), []);
});

check("validateSoundCueGraph reports structural problems", () => {
  const missingOutput = makeCue([{ id: "src", kind: "source", clipId: "c" }], []);
  assert.deepEqual(validateSoundCueGraph(missingOutput), ["Missing output node"]);

  const twoOutputs = makeCue(
    [
      { id: "out1", kind: "output" },
      { id: "out2", kind: "output" },
      { id: "src", kind: "source", clipId: "c" },
    ],
    [{ from: "src", to: "out1" }],
  );
  assert.ok(validateSoundCueGraph(twoOutputs).includes("Multiple output nodes"));

  const dangling = makeCue(
    [
      { id: "out", kind: "output" },
      { id: "src", kind: "source", clipId: "c" },
    ],
    [
      { from: "src", to: "out" },
      { from: "ghost", to: "out" },
    ],
  );
  assert.ok(
    validateSoundCueGraph(dangling).includes("Connection references missing node: ghost"),
  );

  const noClip = makeCue(
    [
      { id: "out", kind: "output" },
      { id: "src", kind: "source", clipId: "" },
    ],
    [{ from: "src", to: "out" }],
  );
  assert.ok(validateSoundCueGraph(noClip).includes('Source node "src" has no clipId'));

  const orphanOutput = makeCue([{ id: "out", kind: "output" }], []);
  assert.ok(validateSoundCueGraph(orphanOutput).includes("Output node has no connected inputs"));
});

check("starter SC_Footstep_Stone cue validates and evaluates to one clip", () => {
  const raw = JSON.parse(
    readFileSync("public/assets/starter-content/Sounds/SC_Footstep_Stone.soundcue.json", "utf8"),
  ) as SoundCueAsset;
  assert.deepEqual(validateSoundCueGraph(raw), []);
  assert.deepEqual(evaluateSoundCue(raw), [
    { clipId: "starter-snd-footstep-stone", volume: 1, pitch: 1, loop: false, delaySeconds: 0 },
  ]);
});

// --- Dialogue & Voice (D1: resolver + subsystem) ------------------------------

const dvNarrator: DialogueVoiceAsset = {
  schema: 1,
  type: "dialogueVoice",
  id: "narrator",
  name: "Narrator",
  displayName: "The Narrator",
};
const dlHello: DialogueLineAsset = {
  schema: 1,
  type: "dialogueLine",
  id: "line-1",
  spokenText: "Hello there, traveler.",
  contexts: [
    { speakerVoiceId: "narrator", audioSourceId: "snd-generic", audioSourceType: "sound" },
    { speakerVoiceId: "narrator", locale: "en", audioSourceId: "snd-en", audioSourceType: "sound" },
  ],
};
const engineTick = (subsystem: DialogueSubsystem, dt: number, frame: number): void => {
  subsystem.update({ deltaSeconds: dt, elapsedSeconds: dt * frame, frame });
};

check("resolveDialogueLine picks locale/speaker context and falls back to subtitle-only", () => {
  const en = resolveDialogueLine(dlHello, { locale: "en" });
  assert.equal(en.matchedContextIndex, 1);
  assert.equal(en.audioSourceId, "snd-en");
  // A locale with no exact mapping falls back to the locale-agnostic recording.
  assert.equal(resolveDialogueLine(dlHello, { locale: "fr" }).audioSourceId, "snd-generic");
  // A speaker the line has no mapping for still resolves to subtitle-only text.
  const noMatch = resolveDialogueLine(dlHello, { speakerVoiceId: "villain" });
  assert.equal(noMatch.matchedContextIndex, -1);
  assert.equal(noMatch.audioSourceId, undefined);
  assert.equal(noMatch.subtitleText, "Hello there, traveler.");
});

check("resolveDialogueLine prefers a directed-target mapping and honors subtitle override", () => {
  const directed: DialogueLineAsset = {
    schema: 1,
    type: "dialogueLine",
    id: "d",
    spokenText: "spoken",
    subtitleText: "shown",
    contexts: [
      { speakerVoiceId: "narrator", audioSourceId: "generic" },
      { speakerVoiceId: "narrator", targetVoiceIds: ["player"], audioSourceId: "to-player" },
    ],
  };
  assert.equal(resolveDialogueLine(directed, { targetVoiceId: "player" }).audioSourceId, "to-player");
  // No context → earliest mapping on a score tie; subtitleText overrides spokenText.
  const plain = resolveDialogueLine(directed, {});
  assert.equal(plain.audioSourceId, "generic");
  assert.equal(plain.subtitleText, "shown");
});

check("estimateSubtitleDurationSeconds scales with length and clamps", () => {
  assert.equal(estimateSubtitleDurationSeconds(""), 1.5); // min floor
  assert.equal(estimateSubtitleDurationSeconds("a".repeat(10000)), 12); // max ceil
  assert.ok(Math.abs(estimateSubtitleDurationSeconds("a".repeat(90)) - 6.6) < 1e-9); // 0.6 + 90/15
});

check("validateDialogueVoice/Line flag structural problems", () => {
  assert.deepEqual(validateDialogueVoice(dvNarrator), []);
  const badVoice: DialogueVoiceAsset = {
    schema: 1,
    type: "dialogueVoice",
    id: "v",
    name: "V",
    gender: "robot" as DialogueVoiceAsset["gender"],
  };
  assert.ok(validateDialogueVoice(badVoice).some((i) => i.includes("invalid gender")));

  const bad: DialogueLineAsset = { schema: 1, type: "dialogueLine", id: "bad", spokenText: "", contexts: [] };
  const issues = validateDialogueLine(bad);
  assert.ok(issues.some((i) => i.includes("no spokenText")));
  assert.ok(issues.some((i) => i.includes("no context mappings")));

  const dupKey: DialogueLineAsset = {
    schema: 1,
    type: "dialogueLine",
    id: "dup",
    spokenText: "Hi",
    contexts: [
      { speakerVoiceId: "a", localizationKey: "k" },
      { speakerVoiceId: "a", localizationKey: "k" },
    ],
  };
  assert.ok(validateDialogueLine(dupKey).some((i) => i.includes("repeats localizationKey")));

  const missingVoice: DialogueLineAsset = {
    schema: 1,
    type: "dialogueLine",
    id: "mv",
    spokenText: "Hi",
    contexts: [{ speakerVoiceId: "ghost" }],
  };
  assert.ok(
    validateDialogueLine(missingVoice, { voiceIds: new Set(["real"]) }).some((i) =>
      i.includes("missing speaker voice"),
    ),
  );
});

check("DialogueSubsystem.playLine shows a subtitle and ends after the audio duration", () => {
  const events: DialogueSubtitleEvent[] = [];
  const hidden: string[] = [];
  const ended: { lineId: string; interrupted: boolean }[] = [];
  const played: string[] = [];
  const subsystem = new DialogueSubsystem({
    voices: [dvNarrator],
    lines: [dlHello],
    playAudio: (req) => {
      played.push(req.sourceId);
      return { stop: () => undefined, durationSeconds: 2 } satisfies DialogueAudioPlayback;
    },
    onSubtitleShow: (event) => events.push(event),
    onSubtitleHide: (lineId) => hidden.push(lineId),
    onLineEnd: (info) => ended.push(info),
  });
  const result = subsystem.playLine("line-1", { locale: "en" });
  assert.equal(result.played, true);
  assert.equal(result.hasAudio, true);
  assert.equal(result.durationSeconds, 2); // audio-reported duration wins over the estimate
  assert.deepEqual(played, ["snd-en"]);
  assert.equal(events.length, 1);
  assert.equal(events[0]?.text, "Hello there, traveler.");
  assert.equal(events[0]?.speakerName, "The Narrator");
  assert.deepEqual(subsystem.activeLineIds(), ["line-1"]);
  engineTick(subsystem, 1, 1); // not yet elapsed
  assert.deepEqual(subsystem.activeLineIds(), ["line-1"]);
  engineTick(subsystem, 1.5, 2); // elapses
  assert.deepEqual(hidden, ["line-1"]);
  assert.deepEqual(ended, [{ lineId: "line-1", interrupted: false }]);
  assert.deepEqual(subsystem.activeLineIds(), []);
});

check("DialogueSubsystem estimates subtitle duration when a line has no audio", () => {
  const subtitleOnly: DialogueLineAsset = {
    schema: 1,
    type: "dialogueLine",
    id: "bark",
    spokenText: "Hey!",
    contexts: [{ speakerVoiceId: "narrator" }],
  };
  let shown: DialogueSubtitleEvent | null = null;
  const subsystem = new DialogueSubsystem({
    voices: [dvNarrator],
    lines: [subtitleOnly],
    playAudio: () => null,
    onSubtitleShow: (event) => {
      shown = event;
    },
  });
  const result = subsystem.playLine("bark");
  assert.equal(result.hasAudio, false);
  assert.equal(result.durationSeconds, estimateSubtitleDurationSeconds("Hey!"));
  assert.equal(shown?.durationSeconds, estimateSubtitleDurationSeconds("Hey!"));
});

check("DialogueSubsystem.stopLine interrupts audio and hides the subtitle", () => {
  let stopped = false;
  const ended: { lineId: string; interrupted: boolean }[] = [];
  const subsystem = new DialogueSubsystem({
    voices: [dvNarrator],
    lines: [dlHello],
    playAudio: () => ({
      stop: () => {
        stopped = true;
      },
      durationSeconds: 5,
    }),
    onLineEnd: (info) => ended.push(info),
  });
  subsystem.playLine("line-1", { locale: "en" });
  subsystem.stopLine("line-1");
  assert.equal(stopped, true);
  assert.deepEqual(ended, [{ lineId: "line-1", interrupted: true }]);
  assert.deepEqual(subsystem.activeLineIds(), []);
});

check("DialogueSubsystem.playLine returns not-played for an unknown line", () => {
  const subsystem = new DialogueSubsystem();
  assert.deepEqual(subsystem.playLine("nope"), {
    played: false,
    hasAudio: false,
    durationSeconds: 0,
  });
});

// NOTE: the "starter dialogue assets" check was removed with the starter-content
// cleanup (DV_Narrator/DL_Welcome demo files deleted from public/assets). The
// dialogue voice/line parsers stay covered by the inline-fixture checks below.

// --- Dialogue & Voice (D4: localization + production pipeline) ----------------

check("resolveDialogueLine localizes the subtitle by localizationKey with authored fallback", () => {
  const line: DialogueLineAsset = {
    schema: 1,
    type: "dialogueLine",
    id: "loc-line",
    spokenText: "Hello there.",
    contexts: [{ speakerVoiceId: "narrator", locale: "en", localizationKey: "greet" }],
  };
  const tr: DialogueLocalizationSource = {
    resolveSubtitle: (key) => (key === "greet" ? "Merhaba." : undefined),
  };
  assert.equal(resolveDialogueLine(line, {}, tr).subtitleText, "Merhaba.");
  // A missing key leaves the authored text in place (fallback policy).
  assert.equal(
    resolveDialogueLine(line, {}, { resolveSubtitle: () => undefined }).subtitleText,
    "Hello there.",
  );
  // No source at all → authored text (localization is optional).
  assert.equal(resolveDialogueLine(line, {}).subtitleText, "Hello there.");
});

check("resolveDialogueLine applies a per-locale recording override, else keeps the mapping audio", () => {
  const line: DialogueLineAsset = {
    schema: 1,
    type: "dialogueLine",
    id: "loc-audio",
    spokenText: "Hi",
    contexts: [
      { speakerVoiceId: "narrator", audioSourceId: "snd-en", localizationKey: "hi" },
    ],
  };
  const override: DialogueLocalizationSource = {
    resolveSubtitle: () => undefined,
    resolveAudio: (key) => (key === "hi" ? { sourceId: "snd-tr", sourceType: "soundCue" } : undefined),
  };
  const localized = resolveDialogueLine(line, {}, override);
  assert.equal(localized.audioSourceId, "snd-tr");
  assert.equal(localized.audioSourceType, "soundCue");
  // No override → the authored recording (and its type) survive.
  const plain = resolveDialogueLine(line, {}, { resolveSubtitle: () => undefined });
  assert.equal(plain.audioSourceId, "snd-en");
  assert.equal(plain.audioSourceType, "sound");
});

check("DialogueSubsystem.playLine localizes the subtitle and setLocalization(undefined) reverts", () => {
  const line: DialogueLineAsset = {
    schema: 1,
    type: "dialogueLine",
    id: "l",
    spokenText: "Hello.",
    contexts: [{ speakerVoiceId: "narrator", localizationKey: "greet" }],
  };
  let shown: DialogueSubtitleEvent | null = null;
  const subsystem = new DialogueSubsystem({
    voices: [dvNarrator],
    lines: [line],
    localization: { resolveSubtitle: (key) => (key === "greet" ? "Merhaba." : undefined) },
    onSubtitleShow: (event) => {
      shown = event;
    },
  });
  subsystem.playLine("l");
  assert.equal((shown as DialogueSubtitleEvent | null)?.text, "Merhaba.");
  subsystem.stopAll();
  subsystem.setLocalization(undefined);
  subsystem.playLine("l");
  assert.equal((shown as DialogueSubtitleEvent | null)?.text, "Hello.");
});

