check("goal-reached behavior: fires once on overlap begin, plays its cue, signals the shell", () => {
  const reached: string[] = [];
  const registry = createBehaviorRegistry({ onGoalReached: (id) => reached.push(id) });
  const physics = new PhysicsSubsystem();
  const audio = new AudioSubsystem();
  const goal: Entity = {
    id: "goal:0",
    components: {
      Transform: { position: [0, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
      Collider: { shape: "box", size: [1, 1, 1], isStatic: true, isSensor: true },
      [EVENT_BINDINGS_COMPONENT]: {
        bindings: [{ event: "overlap", scriptId: "goal-reached" }],
      },
      Audio: { clipId: "collision-chime", volume: 0.6, loop: false, spatial: false },
    },
  };
  const player: Entity = {
    id: "player:0",
    components: {
      Transform: { position: [5, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
      Collider: { shape: "box", size: [1, 1, 1], isStatic: false, isSensor: false },
    },
  };
  physics.setEntities([goal, player]);
  const behavior = new BehaviorSubsystem(registry, new ActionMap({}), () => undefined, physics, audio);
  behavior.setEntities([goal, player]);
  const app = new EngineApp();
  app.registerSubsystem(physics);
  app.registerSubsystem(behavior);
  app.registerSubsystem(audio);

  // The sensor goal never blocks movement, and far away there is no trigger.
  assert.equal(physics.staticBlockerAabbs().length, 0);
  app.update(0.016);
  assert.deepEqual(reached, []);
  assert.deepEqual(audio.playedRequests(), []);

  // Walk the player onto the goal and tick twice: the overlap begin fires exactly once.
  physics.setEntityTransform("player:0", {
    position: [0, 0, 0],
    rotation: [0, 0, 0],
    scale: [1, 1, 1],
  });
  app.update(0.016);
  app.update(0.016);
  assert.deepEqual(reached, ["goal:0"]);
  assert.deepEqual(audio.playedRequests(), [
    { clipId: "collision-chime", volume: 0.6, loop: false, spatial: false },
  ]);
});

// P2 Level Travel: the `level-travel` sensor listens to the overlap begin event,
// reading its destination level/spawn from the authored params and signalling the
// shell exactly once so the teardown/rebuild it kicks off is never re-entered by
// a lingering overlap.
check("level-travel behavior: fires once on overlap begin with the authored target + spawn", () => {
  const travels: Array<{ id: string; level: string; spawn?: string }> = [];
  const registry = createBehaviorRegistry({
    onLevelTravel: (id, level, spawn) => travels.push({ id, level, spawn }),
  });
  const physics = new PhysicsSubsystem();
  const audio = new AudioSubsystem();
  const portal: Entity = {
    id: "portal:0",
    components: {
      Transform: { position: [0, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
      Collider: { shape: "box", size: [1, 1, 1], isStatic: true, isSensor: true },
      [EVENT_BINDINGS_COMPONENT]: {
        bindings: [
          {
            event: "overlap",
            scriptId: "level-travel",
            params: { targetLevel: "Levels/TestLevel.level.json", targetSpawn: "fromPlayground" },
          },
        ],
      },
    },
  };
  const player: Entity = {
    id: "player:0",
    components: {
      Transform: { position: [5, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
      Collider: { shape: "box", size: [1, 1, 1], isStatic: false, isSensor: false },
    },
  };
  physics.setEntities([portal, player]);
  const behavior = new BehaviorSubsystem(registry, new ActionMap({}), () => undefined, physics, audio);
  behavior.setEntities([portal, player]);
  const app = new EngineApp();
  app.registerSubsystem(physics);
  app.registerSubsystem(behavior);

  // A sensor portal never blocks; far away there is no contact, so no travel.
  assert.equal(physics.staticBlockerAabbs().length, 0);
  app.update(0.016);
  assert.deepEqual(travels, []);

  // Walk onto the portal and tick twice: the overlap begin requests travel exactly once.
  physics.setEntityTransform("player:0", { position: [0, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] });
  app.update(0.016);
  app.update(0.016);
  assert.deepEqual(travels, [
    { id: "portal:0", level: "Levels/TestLevel.level.json", spawn: "fromPlayground" },
  ]);
});

// Regression: a legacy *flat* `Behavior` trigger (a `shape:*` volume authored via
// `placement.behavior`, not an EventBindings overlap binding) fires as a per-frame
// `tick`, not on an overlap event. The subsystem now hands every tick a synthetic
// `{ kind: "tick" }` envelope, so `triggerOverlapBegins` must route a tick to the
// physics contact-polling fallback — otherwise the player pawn can stand inside a
// checkpoint/level-travel sensor and it never fires (the real runtime gap behind
// the Player Start default pawn: it overlaps the sensor but nothing happened).
check("checkpoint behavior: a flat tick Behavior fires from physics contact polling", () => {
  const saves: Array<{ id: string; slot: string }> = [];
  const registry = createBehaviorRegistry({
    onCheckpoint: (id, slot) => saves.push({ id, slot }),
  });
  const physics = new PhysicsSubsystem();
  const audio = new AudioSubsystem();
  const trigger: Entity = {
    id: "checkpoint:0",
    components: {
      Transform: { position: [0, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
      Collider: { shape: "box", size: [2, 2, 2], isStatic: true, isSensor: true },
      // Flat Behavior (tick), NOT an EventBindings overlap binding.
      [BEHAVIOR_COMPONENT]: { scriptId: "checkpoint", params: { slot: "quick" } },
    },
  };
  const player: Entity = {
    id: "player:0",
    components: {
      Transform: { position: [5, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
      Collider: { shape: "box", size: [1, 1, 1], isStatic: false, isSensor: false },
    },
  };
  physics.setEntities([trigger, player]);
  const behavior = new BehaviorSubsystem(registry, new ActionMap({}), () => undefined, physics, audio);
  behavior.setEntities([trigger, player]);
  const app = new EngineApp();
  app.registerSubsystem(physics);
  app.registerSubsystem(behavior);

  // Apart: no contact, so the tick fallback saves nothing.
  app.update(0.016);
  assert.deepEqual(saves, []);

  // Overlap the sensor: the flat tick behavior polls the live contact and writes
  // the checkpoint exactly once, even though no overlap *event* is delivered to it.
  physics.setEntityTransform("player:0", { position: [0, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] });
  app.update(0.016);
  app.update(0.016);
  assert.deepEqual(saves, [{ id: "checkpoint:0", slot: "quick" }]);
});

check("level-travel behavior: fresh scene registry lets the same trigger id fire again", () => {
  const travels: Array<{ id: string; level: string }> = [];
  const createRegistry = (): BehaviorRegistry =>
    createBehaviorRegistry({
      onLevelTravel: (id, level) => travels.push({ id, level }),
    });
  const physics = new PhysicsSubsystem();
  const behavior = new BehaviorSubsystem(createRegistry(), new ActionMap({}), () => undefined, physics);
  const portal: Entity = {
    id: "portal:0",
    components: {
      Transform: { position: [0, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
      Collider: { shape: "box", size: [1, 1, 1], isStatic: true, isSensor: true },
      [EVENT_BINDINGS_COMPONENT]: {
        bindings: [
          {
            event: "overlap",
            scriptId: "level-travel",
            params: { targetLevel: "Levels/TestLevel.level.json" },
          },
        ],
      },
    },
  };
  const player: Entity = {
    id: "player:0",
    components: {
      Transform: { position: [0, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
      Collider: { shape: "box", size: [1, 1, 1], isStatic: false, isSensor: false },
    },
  };
  const entities = [portal, player];
  const app = new EngineApp();
  app.registerSubsystem(physics);
  app.registerSubsystem(behavior);

  physics.setEntities(entities);
  behavior.setEntities(entities);
  app.update(0.016);
  app.update(0.016);

  physics.setEntities([]);
  behavior.setRegistry(createRegistry());
  physics.setEntities(entities);
  behavior.setEntities(entities);
  app.update(0.016);
  app.update(0.016);

  assert.deepEqual(travels, [
    { id: "portal:0", level: "Levels/TestLevel.level.json" },
    { id: "portal:0", level: "Levels/TestLevel.level.json" },
  ]);
});

