check("parseRuntimeParticleEffect collapses a schema-1 effect and rejects bad input", () => {
  // A schema-1 body collapses to the flat runtime params the renderer needs
  // (effectId is dropped — the manifest is the id source of truth).
  assert.deepEqual(
    parseRuntimeParticleEffect({
      schema: 1,
      effectId: "starter-fx-smoke-puff",
      name: "Smoke Puff Effect",
      loop: false,
      rate: 18,
      lifetime: 0.8,
      startSize: 0.12,
      endSize: 0.8,
      velocity: [0, 1, 0],
      spread: 0.4,
      materialMode: "alpha",
      color: "#a7a7a7",
    }),
    {
      name: "Smoke Puff Effect",
      loop: false,
      rate: 18,
      lifetime: 0.8,
      startSize: 0.12,
      endSize: 0.8,
      velocity: [0, 1, 0],
      spread: 0.4,
      materialMode: "alpha",
      color: "#a7a7a7",
    },
  );
  // Non-object, unknown schema, or empty schema-1 effectId â†’ null.
  assert.equal(parseRuntimeParticleEffect(null), null);
  assert.equal(parseRuntimeParticleEffect({ schema: 3 }), null);
  assert.equal(parseRuntimeParticleEffect({ schema: 1, effectId: "" }), null);
  // Unknown materialMode falls back to alpha; a malformed color falls back to white.
  const fallback = parseRuntimeParticleEffect({
    schema: 1,
    effectId: "fx",
    materialMode: "neon",
    color: "red",
  });
  assert.equal(fallback?.materialMode, "alpha");
  assert.equal(fallback?.color, "#ffffff");
});

check("normalizeEffectDefinition reads a schema-2 effect and applies defaults", () => {
  const def = normalizeEffectDefinition({
    schema: 2,
    type: "particleEffect",
    name: "Smoke Puff Effect",
    category: "Smoke",
    tags: ["smoke"],
    system: { loop: true, duration: 0.35, maxParticles: 96 },
    spawn: { mode: "burst", count: 30, shape: "sphere", radius: 0.12 },
    initialize: { lifetime: [0.5, 1.1], startColor: "#bfc3c8", speed: [0.7, 1.8], spreadAngleDeg: 42 },
    update: { endColor: "#6d7378", endSize: [0.55, 0.95] },
    renderer: { blendMode: "additive", softness: 0.6 },
  });
  assert.ok(def);
  assert.equal(def.name, "Smoke Puff Effect");
  assert.equal(def.category, "Smoke");
  assert.deepEqual(def.tags, ["smoke"]);
  assert.equal(def.system.loop, true);
  assert.equal(def.system.maxParticles, 96);
  assert.equal(def.spawn.mode, "burst");
  assert.equal(def.spawn.count, 30);
  assert.equal(def.spawn.shape, "sphere");
  assert.deepEqual(def.initialize.lifetime, [0.5, 1.1]);
  assert.equal(def.initialize.startColor, "#bfc3c8");
  assert.equal(def.renderer.blendMode, "additive");
  // Untouched fields fall back to §6 defaults, not undefined.
  assert.deepEqual(def.initialize.startSize, [0.1, 0.2]);
  assert.equal(def.update.fadeOutTime, 0.1);
  assert.equal(def.renderer.sortMode, "none");

  // An out-of-order range is reordered min<=max; a single number widens to [n,n];
  // a bad enum/color falls back; missing sub-blocks default whole-cloth.
  const messy = normalizeEffectDefinition({
    schema: 2,
    initialize: { lifetime: [1.2, 0.4], startSize: 0.3, startColor: "nope" },
    renderer: { blendMode: "screen" },
  });
  assert.ok(messy);
  assert.deepEqual(messy.initialize.lifetime, [0.4, 1.2]);
  assert.deepEqual(messy.initialize.startSize, [0.3, 0.3]);
  assert.equal(messy.initialize.startColor, "#ffffff");
  assert.equal(messy.renderer.blendMode, "alpha");
});

check("renderer.texture (VFX Lite Faz 6a) normalizes and collapses through to runtime", () => {
  // A texture asset id is preserved on the normalized def and carried to the flat
  // runtime effect so the app boundary can resolve it to a sprite URL.
  const textured = normalizeEffectDefinition({
    schema: 2,
    type: "particleEffect",
    renderer: { blendMode: "additive", texture: "fire-01-2" },
  });
  assert.ok(textured);
  assert.equal(textured.renderer.texture, "fire-01-2");
  assert.equal(parseRuntimeParticleEffect({
    schema: 2,
    type: "particleEffect",
    renderer: { blendMode: "additive", texture: "fire-01-2" },
  })?.texture, "fire-01-2");

  // Empty / whitespace / non-string → null, and the runtime effect omits `texture`.
  const bare = normalizeEffectDefinition({ schema: 2, renderer: { texture: "   " } });
  assert.ok(bare);
  assert.equal(bare.renderer.texture, null);
  assert.equal(toRuntimeParticleEffect(bare).texture, undefined);

  // A schema-1 body has no texture concept → null on the def, absent at runtime.
  const legacy = parseRuntimeParticleEffect({ schema: 1, effectId: "fx", color: "#ffffff" });
  assert.ok(legacy);
  assert.equal("texture" in legacy, false);

  // validateEffectAsset (save path) keeps the texture through the round-trip.
  const canonical = validateEffectAsset({
    schema: 2,
    type: "particleEffect",
    renderer: { blendMode: "additive", texture: "fire-01-2" },
  }) as { renderer: { texture: string | null } };
  assert.equal(canonical.renderer.texture, "fire-01-2");
});

check("renderer.subUV flipbook (VFX Lite Faz 6b) normalizes, clamps, and collapses", () => {
  // Default grid is 1×1 (whole texture, no animation) when absent.
  const bare = normalizeEffectDefinition({ schema: 2, type: "particleEffect" });
  assert.ok(bare);
  assert.deepEqual(bare.renderer.subUV, { cols: 1, rows: 1 });

  // cols/rows round to ints and clamp to [1, 32].
  const grid = normalizeEffectDefinition({
    schema: 2,
    renderer: { subUV: { cols: 6.4, rows: 0 } },
  });
  assert.ok(grid);
  assert.deepEqual(grid.renderer.subUV, { cols: 6, rows: 1 });
  const huge = normalizeEffectDefinition({ schema: 2, renderer: { subUV: { cols: 999, rows: 8 } } });
  assert.deepEqual(huge?.renderer.subUV, { cols: 32, rows: 8 });

  // Collapse emits the grid only when it animates (frames > 1); 1×1 is omitted.
  const animated = parseRuntimeParticleEffect({
    schema: 2,
    type: "particleEffect",
    renderer: { texture: "t-fire-subuv", subUV: { cols: 6, rows: 6 } },
  });
  assert.deepEqual(animated?.subUV, { cols: 6, rows: 6 });
  const still = parseRuntimeParticleEffect({
    schema: 2,
    type: "particleEffect",
    renderer: { texture: "fire-01-2", subUV: { cols: 1, rows: 1 } },
  });
  assert.equal(still?.subUV, undefined);

  // validateEffectAsset (save path) keeps the grid through the round-trip.
  const canonical = validateEffectAsset({
    schema: 2,
    type: "particleEffect",
    renderer: { texture: "t-fire-subuv", subUV: { cols: 6, rows: 6 } },
  }) as { renderer: { subUV: { cols: number; rows: number } } };
  assert.deepEqual(canonical.renderer.subUV, { cols: 6, rows: 6 });
});

