check("normalizeEffectDefinition maps burst count to an approximate runtime rate", () => {
  const runtime = toRuntimeParticleEffect(
    normalizeEffectDefinition({
      schema: 2,
      system: { loop: false },
      spawn: { mode: "burst", count: 30 },
      initialize: { lifetime: [1, 1] },
    })!,
  );
  // burst count 30 over a ~1s lifetime window â†’ ~30/s continuous approximation.
  assert.equal(runtime.rate, 30);
});

// VFX Lite Faz 3 — the preview viewport reads alive/capacity off the runtime
// ParticleEffect to drive its HUD, so those counts must track the simulation.
function runtimeFx(overrides: Partial<RuntimeParticleEffect> = {}): RuntimeParticleEffect {
  return {
    loop: false,
    rate: 10,
    lifetime: 1,
    startSize: 0.2,
    endSize: 0.2,
    velocity: [0, 1, 0],
    spread: 0,
    materialMode: "alpha",
    color: "#ffffff",
    ...overrides,
  };
}

check("ParticleEffect reports capacity and never exceeds it while alive", () => {
  // capacity = max(8, ceil(rate*lifetime)+4). Idle emitters still get the floor.
  assert.equal(new ParticleEffect(runtimeFx({ rate: 0, lifetime: 1 })).maxCapacity, 8);
  const fx = new ParticleEffect(runtimeFx({ loop: true, rate: 10, lifetime: 1 }));
  assert.equal(fx.maxCapacity, 14);
  assert.equal(fx.aliveCount(), 0);
  fx.update(0.5); // spawnAccumulator 5 → 5 particles, aged 0.5s (none expired yet)
  assert.equal(fx.aliveCount(), 5);
  fx.dispose();

  // A dense emitter drops spawns rather than overrunning the buffer.
  const dense = new ParticleEffect(runtimeFx({ loop: true, rate: 1000, lifetime: 1 }));
  for (let i = 0; i < 10; i += 1) dense.update(0.1);
  assert.ok(dense.aliveCount() <= dense.maxCapacity);
  dense.dispose();
});

check("ParticleEffect density scale thins the spawn rate (quality knob)", () => {
  // rate 10, dt 0.5 → 5 spawns at full density.
  const full = new ParticleEffect(runtimeFx({ loop: true, rate: 10, lifetime: 1 }));
  full.update(0.5);
  assert.equal(full.aliveCount(), 5);
  full.dispose();

  // Density 0.5 halves the effective rate: 10 * 0.5 * 0.5 = 2.5 → 2 particles.
  const half = new ParticleEffect(runtimeFx({ loop: true, rate: 10, lifetime: 1 }));
  half.setDensityScale(0.5);
  half.update(0.5);
  assert.equal(half.aliveCount(), 2);

  // Density 0 suppresses emission entirely; bad input falls back to full density.
  half.setDensityScale(0);
  half.reset();
  half.update(1);
  assert.equal(half.aliveCount(), 0);
  half.setDensityScale(Number.NaN);
  half.update(0.1); // 10 * 1 * 0.1 = 1
  assert.equal(half.aliveCount(), 1);
  half.dispose();
});

check("ParticleEffect one-shot drains to zero alive and reports finished", () => {
  const fx = new ParticleEffect(runtimeFx({ loop: false, rate: 20, lifetime: 0.5 }));
  assert.equal(fx.isFinished(), false);
  fx.update(0.25);
  assert.ok(fx.aliveCount() > 0); // emitting inside the one lifetime window
  // Run well past the emission window + lifetime; every particle must age out.
  for (let i = 0; i < 40; i += 1) fx.update(0.05);
  assert.equal(fx.aliveCount(), 0);
  assert.equal(fx.isFinished(), true);
  fx.dispose(); // dispose after a full lifecycle must not throw
});

check("ParticleEffect dispose is safe and instances hold independent buffers", () => {
  const a = new ParticleEffect(runtimeFx({ loop: true, rate: 30, lifetime: 1 }));
  const b = new ParticleEffect(runtimeFx({ loop: true, rate: 30, lifetime: 1 }));
  // Distinct Three.js objects — rebuilding in the preview never shares buffers.
  assert.notEqual(a.object3D, b.object3D);
  assert.notEqual(a.object3D.geometry, b.object3D.geometry);
  a.update(0.3);
  assert.ok(a.aliveCount() > 0);
  assert.equal(b.aliveCount(), 0); // advancing one never touches the other
  a.dispose();
  b.dispose();
});

// VFX Lite Faz 4 — a ParticleEmitterComponent applies a small set of per-instance
// overrides (§8) on top of the shared asset. The runtime consumes them here.
check("ParticleEffect applies §8 instance overrides (scale/tint/loop)", () => {
  // tint replaces the effect colour on the shader material's uColor uniform.
  const tinted = new ParticleEffect(runtimeFx({ color: "#ffffff" }), { tint: "#aabbcc" });
  const uColor = (
    tinted.object3D.material as unknown as {
      uniforms: { uColor: { value: { getHexString(): string } } };
    }
  ).uniforms.uColor.value;
  assert.equal(uColor.getHexString(), "aabbcc");
  tinted.dispose();

  // scale grows sizes/velocity but not rate/lifetime, so capacity is unchanged
  // (max(8, ceil(10*1)+4) = 14) — a scaled effect never overruns its buffer.
  const scaled = new ParticleEffect(runtimeFx({ loop: true, rate: 10, lifetime: 1 }), { scale: 3 });
  assert.equal(scaled.maxCapacity, 14);
  scaled.dispose();

  // loop:true override keeps a one-shot asset emitting past its window.
  const forced = new ParticleEffect(runtimeFx({ loop: false, rate: 20, lifetime: 0.3 }), { loop: true });
  for (let i = 0; i < 40; i += 1) forced.update(0.05);
  assert.equal(forced.isFinished(), false);
  assert.ok(forced.aliveCount() > 0);
  forced.dispose();

  // loop:false override forces a looping asset to finish after its window.
  const oneShot = new ParticleEffect(runtimeFx({ loop: true, rate: 20, lifetime: 0.3 }), { loop: false });
  for (let i = 0; i < 40; i += 1) oneShot.update(0.05);
  assert.equal(oneShot.isFinished(), true);
  assert.equal(oneShot.aliveCount(), 0);
  oneShot.dispose();
});

check("ParticleEffect.reset rewinds buffers and re-applies overrides (pool reuse)", () => {
  const fx = new ParticleEffect(runtimeFx({ loop: false, rate: 20, lifetime: 0.3, color: "#ffffff" }));
  for (let i = 0; i < 40; i += 1) fx.update(0.05);
  assert.equal(fx.isFinished(), true);
  assert.equal(fx.aliveCount(), 0);
  // reset rewinds elapsed/buffers and applies a fresh tint override.
  fx.reset({ tint: "#112233" });
  assert.equal(fx.isFinished(), false);
  const uColor = (
    fx.object3D.material as unknown as { uniforms: { uColor: { value: { getHexString(): string } } } }
  ).uniforms.uColor.value;
  assert.equal(uColor.getHexString(), "112233");
  fx.update(0.1); // emits again after reset
  assert.ok(fx.aliveCount() > 0);
  fx.dispose();
});

// VFX Lite Faz 5 — the VfxSubsystem owns every live effect: definition cache,
// pooling, per-frame advance and one-shot recycling. A fixture loader stands in
// for the fetch so the lifecycle is exercised headlessly.
function makeVfx(def: RuntimeParticleEffect | null = runtimeFx({ loop: false, rate: 20, lifetime: 0.3 })) {
  let loads = 0;
  const vfx = new VfxSubsystem({
    resolveEffectUrl: (id) => (id === "fx" ? "mem://fx" : null),
    loadDefinition: async () => {
      loads += 1;
      return def;
    },
  });
  return { vfx, loads: () => loads };
}

await checkAsync("VfxSubsystem warms, plays, advances and recycles a one-shot into the pool", async () => {
  const { vfx } = makeVfx();
  // Playing before warming spawns nothing (returns null) but kicks off a warm.
  assert.equal(vfx.play("fx"), null);
  assert.ok(await vfx.warm("fx"));
  const id = vfx.play("fx", { position: [1, 2, 3] });
  assert.ok(id !== null);
  assert.equal(vfx.root.children.length, 1);
  assert.equal(vfx.getDebugSnapshot().activeInstances, 1);
  vfx.advance(0.1);
  assert.ok(vfx.getDebugSnapshot().aliveParticles > 0);
  // Advance well past the emission window + lifetime → finishes and recycles.
  for (let i = 0; i < 40; i += 1) vfx.advance(0.05);
  const snap = vfx.getDebugSnapshot();
  assert.equal(snap.activeInstances, 0);
  assert.equal(vfx.root.children.length, 0);
  assert.equal(snap.pooledInstances, 1);
  vfx.dispose();
});

await checkAsync("VfxSubsystem reuses the pooled effect object on the next play", async () => {
  const { vfx } = makeVfx();
  await vfx.warm("fx");
  const id1 = vfx.play("fx")!;
  const pointsObject = vfx.root.children[0];
  for (let i = 0; i < 40; i += 1) vfx.advance(0.05); // drain → pooled
  assert.equal(vfx.getDebugSnapshot().pooledInstances, 1);
  const id2 = vfx.play("fx")!;
  assert.notEqual(id1, id2);
  assert.equal(vfx.root.children.length, 1);
  assert.equal(vfx.root.children[0], pointsObject); // same Three object reused
  assert.equal(vfx.getDebugSnapshot().pooledInstances, 0);
  vfx.dispose();
});

await checkAsync("VfxSubsystem de-dupes warms, freezes on setEnabled, stops on demand", async () => {
  const { vfx, loads } = makeVfx(runtimeFx({ loop: true, rate: 10, lifetime: 1 }));
  await vfx.warm("fx");
  await vfx.warm("fx"); // cached → no second load
  assert.equal(loads(), 1);
  const id = vfx.play("fx")!;
  vfx.advance(0.3);
  const alive = vfx.getDebugSnapshot().aliveParticles;
  assert.ok(alive > 0);
  // setEnabled(false) freezes the sim + hides the object.
  vfx.setEnabled(id, false);
  assert.equal(vfx.getDebugSnapshot().instances[0]?.enabled, false);
  vfx.advance(0.3);
  assert.equal(vfx.getDebugSnapshot().aliveParticles, alive); // frozen, not advanced
  // A looping effect never finishes on its own; stop() removes it (idempotent).
  vfx.stop(id);
  assert.equal(vfx.getDebugSnapshot().activeInstances, 0);
  vfx.stop(id);
  vfx.dispose();
});

await checkAsync("VfxSubsystem plays nothing for an unknown effect id and disposes cleanly", async () => {
  const { vfx } = makeVfx();
  assert.equal(await vfx.warm("nope"), null); // resolveEffectUrl → null (cached miss)
  assert.equal(vfx.play("nope"), null);
  assert.equal(vfx.getDebugSnapshot().activeInstances, 0);
  // dispose empties instances, pool and caches (defs reset to zero).
  await vfx.warm("fx");
  vfx.play("fx");
  vfx.dispose();
  const snap = vfx.getDebugSnapshot();
  assert.equal(snap.activeInstances, 0);
  assert.equal(snap.pooledInstances, 0);
  assert.equal(snap.cachedDefinitions, 0);
});

check("formatVfxDebug renders counts and busiest instances, tagging disabled", () => {
  const lines = formatVfxDebug({
    activeInstances: 2,
    aliveParticles: 12,
    pooledInstances: 3,
    cachedDefinitions: 1,
    instances: [
      { id: 1, effectId: "fx.smoke", aliveParticles: 4, enabled: true },
      { id: 2, effectId: "fx.spark", aliveParticles: 8, enabled: false },
    ],
  });
  assert.equal(lines[0], "vfx");
  assert.equal(lines[1], "active:2 alive:12 pool:3 defs:1");
  // Sorted by alive desc: spark (8) before smoke (4); disabled tagged "(off)".
  assert.equal(lines[2], "  fx.spark 8 (off)");
  assert.equal(lines[3], "  fx.smoke 4");
});

check("validateEffectAsset canonicalizes a schema-2 body and guards junk numbers", () => {
  const canonical = validateEffectAsset({
    schema: 2,
    type: "particleEffect",
    name: "FX_Test",
    // Junk that must be dropped/guarded: unknown field, NaN duration, bad enum,
    // out-of-order range, malformed colour.
    bogus: "drop me",
    system: { loop: true, duration: Number.NaN, maxParticles: -5 },
    spawn: { mode: "spiral", count: 12 },
    initialize: { lifetime: [1.5, 0.5], startColor: "chartreuse" },
    renderer: { blendMode: "additive" },
  });
  assert.equal(canonical.schema, 2);
  assert.equal(canonical.type, "particleEffect");
  assert.equal("bogus" in canonical, false);
  const system = canonical.system as Record<string, unknown>;
  assert.equal(system.loop, true);
  assert.equal(system.duration, 0.5); // NaN â†’ default
  assert.equal(system.maxParticles, 1); // clamped to >= 1
  const spawn = canonical.spawn as Record<string, unknown>;
  assert.equal(spawn.mode, "burst"); // unknown enum â†’ default
  const initialize = canonical.initialize as Record<string, unknown>;
  assert.deepEqual(initialize.lifetime, [0.5, 1.5]); // reordered
  assert.equal(initialize.startColor, "#ffffff"); // bad colour â†’ white

  // Envelope gate: wrong schema / type / non-object are hard errors.
  assert.throws(() => validateEffectAsset({ schema: 1, type: "particleEffect" }));
  assert.throws(() => validateEffectAsset({ schema: 2, type: "prefab" }));
  assert.throws(() => validateEffectAsset(null));
});

