check("validateDialogueVoiceAsset keeps allowed fields and rejects bad ones", () => {
  const out = validateDialogueVoiceAsset({
    schema: 1,
    type: "dialogueVoice",
    id: "narrator",
    name: "Narrator",
    displayName: "The Narrator",
    actorId: "npc-1",
    gender: "feminine",
    plurality: "singular",
    localeHints: ["en", "tr", ""],
    extra: "dropped",
  });
  assert.equal(out.extra, undefined); // unknown field dropped
  assert.deepEqual(out.localeHints, ["en", "tr"]); // blank entry dropped
  assert.equal(out.gender, "feminine");
  assert.throws(() =>
    validateDialogueVoiceAsset({ schema: 1, type: "dialogueVoice", id: "x", name: "X", gender: "robot" }),
  );
  assert.throws(() => validateDialogueVoiceAsset({ schema: 1, type: "dialogueVoice", id: "", name: "X" }));
  assert.throws(() => validateDialogueVoiceAsset({ schema: 2, type: "dialogueVoice", id: "x", name: "X" }));
});

check("validateDialogueLineAsset normalizes contexts and drops empty optionals", () => {
  const out = validateDialogueLineAsset({
    schema: 1,
    type: "dialogueLine",
    id: "l1",
    spokenText: "Hi there.",
    subtitleText: "", // empty → dropped
    mature: true,
    contexts: [
      {
        speakerVoiceId: "narrator",
        audioSourceId: "snd-a",
        audioSourceType: "sound",
        locale: "en",
        localizationKey: "k",
        targetVoiceIds: ["player", ""],
      },
      { speakerVoiceId: "narrator", audioSourceId: "" }, // empty audio dropped
    ],
  }) as {
    subtitleText?: string;
    mature?: boolean;
    contexts: Array<Record<string, unknown>>;
  };
  assert.equal(out.subtitleText, undefined);
  assert.equal(out.mature, true);
  assert.equal(out.contexts.length, 2);
  assert.deepEqual(out.contexts[0]?.targetVoiceIds, ["player"]);
  assert.equal(out.contexts[0]?.audioSourceId, "snd-a");
  assert.equal(out.contexts[1]?.audioSourceId, undefined);
  assert.throws(() =>
    validateDialogueLineAsset({ schema: 1, type: "dialogueLine", id: "l", spokenText: "x", contexts: [{}] }),
  );
  assert.throws(() =>
    validateDialogueLineAsset({ schema: 1, type: "dialogueLine", id: "l", spokenText: "", contexts: [] }),
  );
});

check("dialogue save payloads enforce their file extensions and reject traversal", () => {
  const voice = { schema: 1, type: "dialogueVoice", id: "n", name: "N" };
  assert.equal(
    validateSaveDialogueVoicePayload({ path: "assets/d/N.dialoguevoice.json", voice }).path,
    "assets/d/N.dialoguevoice.json",
  );
  assert.throws(() => validateSaveDialogueVoicePayload({ path: "assets/d/N.json", voice }));
  assert.throws(() => validateSaveDialogueVoicePayload({ path: "../evil.dialoguevoice.json", voice }));

  const lineAsset = { schema: 1, type: "dialogueLine", id: "l", spokenText: "hi", contexts: [] };
  assert.equal(
    validateSaveDialogueLinePayload({ path: "assets/d/L.dialogue.json", line: lineAsset }).path,
    "assets/d/L.dialogue.json",
  );
  // A voice-extension path must not pass the line payload check (and vice-versa).
  assert.throws(() =>
    validateSaveDialogueLinePayload({ path: "assets/d/L.dialoguevoice.json", line: lineAsset }),
  );
});

check("content-new 'script' creates a `.actor.json` Actor Script seeded with the parent class", () => {
  const door = resolveContentNewFile({
    kind: "script",
    dir: "assets/blueprints",
    name: "DoorBP",
    parentClass: "pawn",
  });
  assert.equal(door.path, "assets/blueprints/DoorBP.actor.json");
  const def = JSON.parse(door.content ?? "");
  assert.equal(def.type, "actor");
  assert.equal(def.parentClass, "pawn");
  assert.equal(def.name, "DoorBP");
  // Always seeded with a root Transform so the component tree has an anchor.
  assert.deepEqual(def.components, [{ id: "root", component: "Transform", props: {} }]);
  assert.deepEqual(def.eventBindings, []);
  assert.deepEqual(def.interfaces, []);
  assert.deepEqual(def.references, []);
  assert.deepEqual(def.dispatchers, []);
  assert.deepEqual(def.messageBindings, []);
  assert.deepEqual(def.variables, []);

  // No parent class picked falls back to "actor".
  const plain = resolveContentNewFile({ kind: "script", dir: "", name: "Thing" });
  assert.equal(JSON.parse(plain.content ?? "").parentClass, "actor");
  // The payload validator defaults the parent class for scripts too.
  assert.equal(
    validateContentNewPayload({ kind: "script", dir: "", name: "X" }).parentClass,
    "actor",
  );
});

check("content-rename validates payload and rejects extensions / unsafe names", () => {
  const payload = validateContentRenamePayload({ path: "assets/props/chair.glb", name: " Sofa " });
  assert.equal(payload.path, "assets/props/chair.glb");
  assert.equal(payload.name, "Sofa");
  // Plain safe names are allowed in the base name.
  assert.equal(
    validateContentRenamePayload({ path: "assets/a.glb", name: "Light" }).name,
    "Light",
  );
  assert.throws(() => validateContentRenamePayload({ path: "assets/a.glb", name: "Sofa.glb" }));
  assert.throws(() => validateContentRenamePayload({ path: "assets/a.glb", name: "a/b" }));
  assert.throws(() => validateContentRenamePayload({ path: "assets/a.glb", name: "" }));
  assert.throws(() => validateContentRenamePayload({ path: "", name: "Sofa" }));
  assert.throws(() => validateContentRenamePayload({ path: "../escape.glb", name: "Sofa" }));
});

check("content-rename target keeps the extension chain and source directory", () => {
  // Simple single extension.
  const glb = resolveContentRenameTarget({ path: "assets/props/chair.glb", name: "Sofa" });
  assert.equal(glb.to, "assets/props/Sofa.glb");
  assert.equal(glb.ext, ".glb");
  // Compound asset extension is preserved (only the base changes).
  const material = resolveContentRenameTarget({
    path: "assets/Materials/Ground.material.json",
    name: "Stone",
  });
  assert.equal(material.to, "assets/Materials/Stone.material.json");
  assert.equal(material.ext, ".material.json");
  // Extensionless file at the root.
  const bare = resolveContentRenameTarget({ path: "README", name: "Notes" });
  assert.equal(bare.to, "Notes");
  assert.equal(bare.ext, "");
});

