check("createBlockingVolumeObject: translucent fill is not pickable, only the edges are", () => {
  // Unreal-style volume picking — clicking the translucent face must NOT select
  // the brush (it would occlude and steal clicks from everything inside/behind
  // it); only the wireframe edges are clickable.
  const brush = createBlockingVolumeObject({
    name: "Volume",
    hidden: false,
    brushShape: "box",
    size: [2, 2, 2],
    brushSides: 24,
    renderInGame: false,
    color: "#ff8c1a",
    position: [0, 0, 0],
    rotation: [0, 0, 0],
    scale: [1, 1, 1],
  });
  // A ray through the centre of a face hits the fill geometrically but misses the
  // thin edges (threshold kept tiny so it can't graze them): with the fill
  // non-pickable the brush yields no intersection at all.
  const faceRay = new Raycaster(new Vector3(0, 0, 5), new Vector3(0, 0, -1));
  faceRay.params.Line.threshold = 0.01;
  assert.equal(faceRay.intersectObject(brush, true).length, 0);
  // Sanity: the fill mesh exists (visual) but its raycast never records a hit.
  const fill = brush.children.find((child) => child.name === "blocking-volume-fill")!;
  const fillHits: unknown[] = [];
  fill.raycast(faceRay, fillHits as never);
  assert.equal(fillHits.length, 0);
  // The wireframe edges stay pickable: a ray aimed down the x=1,z=1 vertical edge hits.
  const edgeRay = new Raycaster(new Vector3(1, 0, 5), new Vector3(0, 0, -1));
  edgeRay.params.Line.threshold = 0.1;
  assert.ok(edgeRay.intersectObject(brush, true).length > 0);
});

check("validateBlockingVolume allowlists fields and round-trips through validateLayout", () => {
  const volume = validateBlockingVolume({
    id: "bv1",
    position: [1, 2, 3],
    name: "Wall",
    brushShape: "cylinder",
    size: [4, 8, 4],
    brushSides: 6,
    renderInGame: true,
    color: "#102030",
    rotation: [0, 90, 0],
    scale: [2, 1, 1],
    bogusField: "dropped",
  });
  assert.deepEqual(volume, {
    id: "bv1",
    position: [1, 2, 3],
    name: "Wall",
    rotation: [0, 90, 0],
    scale: [2, 1, 1],
    brushShape: "cylinder",
    size: [4, 8, 4],
    brushSides: 6,
    renderInGame: true,
    color: "#102030",
  });
  // A missing id rejects; an invalid brush shape rejects the save.
  assert.throws(() => validateBlockingVolume({ position: [0, 0, 0] }));
  assert.throws(() =>
    validateBlockingVolume({ id: "x", position: [0, 0, 0], brushShape: "stairs" }),
  );
  // brushSides must be a finite number within [3, 128]; it rounds to an integer.
  assert.equal(
    validateBlockingVolume({ id: "x", position: [0, 0, 0], brushSides: 7.6 }).brushSides,
    8,
  );
  assert.throws(() =>
    validateBlockingVolume({ id: "x", position: [0, 0, 0], brushSides: 2 }),
  );
  assert.throws(() =>
    validateBlockingVolume({ id: "x", position: [0, 0, 0], brushSides: 500 }),
  );
  // Regression: moving a brush writes a uniform scale as a scalar (writeScale), so
  // a numeric `scale` must validate — not 400 the whole save.
  assert.equal(
    validateBlockingVolume({ id: "x", position: [0, 0, 0], scale: 1 }).scale,
    1,
  );
  assert.deepEqual(
    validateBlockingVolume({ id: "x", position: [0, 0, 0], scale: [2, 1, 1] }).scale,
    [2, 1, 1],
  );

  const layout = validateLayout({
    schema: 1,
    name: "WithVolume",
    loadGroups: [],
    instances: [],
    characters: [],
    blockingVolumes: [{ id: "bv1", position: [0, 0, 0] }],
  }) as RoomLayout;
  assert.deepEqual(layout.blockingVolumes, [{ id: "bv1", position: [0, 0, 0] }]);
  assert.deepEqual(validateLayout(layout), layout);
});

