  assert.equal(table.locale, "tr");
  assert.equal(table.strings["menu.title"], "Duraklatıldı");
  assert.equal(table.strings.ok, "Tamam");
  assert.equal("bad" in table.strings, false);
  assert.equal("nested" in table.strings, false);
