check("AiBehaviorRunner executes selector/sequence/decorator/wait task and messages", () => {
  const bb = new Blackboard([
    { key: "hasLineOfSight", kind: "boolean", default: false },
    { key: "mode", kind: "string", default: "idle" },
  ]);
  const controller = new AIController("ai:enemy", "enemy", bb);
  const asset = normalizeAiBehaviorTreeAsset({
    schema: 1,
    type: "behaviorTree",
    root: {
      kind: "selector",
      children: [
        {
          kind: "task",
          task: "forge.sendMessage",
          decorators: [{ kind: "blackboard", key: "hasLineOfSight", op: "equals", value: true }],
          params: { type: "enemy.see", payload: { alert: true } },
        },
        {
          kind: "sequence",
          children: [
            { kind: "task", task: "forge.setBlackboard", params: { key: "mode", value: "alert" } },
            { kind: "task", task: "forge.wait", params: { seconds: 0.03 } },
            { kind: "task", task: "forge.sendMessage", params: { type: "enemy.idle-done" } },
          ],
        },
      ],
    },
  });
  const messages: Array<{ type: string; source: string; payload?: Record<string, unknown> }> = [];
  const runner = new AiBehaviorRunner(controller, asset, {
    taskRegistry: createDefaultAiTaskRegistry(),
    emitMessage: (message) => messages.push(message),
  });

  assert.equal(runner.tick({ deltaSeconds: 0.01, elapsedSeconds: 0.01, frame: 1 }), "running");
  assert.equal(bb.getString("mode"), "alert");
  assert.equal(messages.length, 0);
  assert.equal(controller.goal, "forge.wait");
  assert.equal(runner.tick({ deltaSeconds: 0.05, elapsedSeconds: 0.06, frame: 2 }), "success");
  assert.equal(messages[0]?.type, "enemy.idle-done");
  assert.equal(messages[0]?.source, "enemy");
  assert.equal(controller.goal, null);

  bb.set("hasLineOfSight", true);
  assert.equal(runner.tick({ deltaSeconds: 0.01, elapsedSeconds: 0.07, frame: 3 }), "success");
  assert.equal(messages[1]?.type, "enemy.see");
  assert.deepEqual(messages[1]?.payload, { alert: true });
  const debug = runner.getDebugSnapshot();
  assert.equal(debug.lastStatus, "success");
  assert.equal(debug.lastTask, "forge.sendMessage");
  assert.equal(debug.failedDecorator, null);
});

check("AiBehaviorRunner sendMessage cooldown throttles repeated task ticks", () => {
  const bb = new Blackboard([]);
  const controller = new AIController("ai:enemy", "enemy", bb);
  const asset = normalizeAiBehaviorTreeAsset({
    schema: 1,
    type: "behaviorTree",
    root: {
      kind: "task",
      task: "forge.sendMessage",
      params: {
        type: "enemy.attack",
        cooldownSeconds: 0.5,
        payload: { attack: "punch", animation: "Punch" },
      },
    },
  });
  const messages: Array<{ type: string; source: string; payload?: Record<string, unknown> }> = [];
  const runner = new AiBehaviorRunner(controller, asset, {
    taskRegistry: createDefaultAiTaskRegistry(),
    emitMessage: (message) => messages.push(message),
  });

  assert.equal(runner.tick({ deltaSeconds: 0.01, elapsedSeconds: 0, frame: 1 }), "success");
  assert.equal(runner.tick({ deltaSeconds: 0.1, elapsedSeconds: 0.1, frame: 2 }), "success");
  assert.equal(messages.length, 1);
  assert.equal(messages[0]?.type, "enemy.attack");
  assert.deepEqual(messages[0]?.payload, { attack: "punch", animation: "Punch" });

  assert.equal(runner.tick({ deltaSeconds: 0.4, elapsedSeconds: 0.5, frame: 3 }), "success");
  assert.equal(messages.length, 2);
});

check("AiBehaviorRunner distance/cooldown/perception decorators gate their branches", () => {
  const bb = new Blackboard([{ key: "target", kind: "entity", default: null }]);
  const controller = new AIController("ai:enemy", "enemy", bb);
  bb.set("target", "player");
  const asset = normalizeAiBehaviorTreeAsset({
    schema: 1,
    type: "behaviorTree",
    root: {
      kind: "selector",
      children: [
        {
          kind: "task",
          task: "test.attack",
          decorators: [
            { kind: "hasPerceptionStimulus", sense: "sight", requireLineOfSight: true },
            { kind: "distance", key: "target", op: "lte", value: 2 },
            { kind: "cooldown", seconds: 1 },
          ],
        },
        { kind: "task", task: "test.idle" },
      ],
    },
  });
  const log: string[] = [];
  // Pawn at origin; target position resolved from the world by entity id.
  let targetPosition: [number, number, number] = [10, 0, 0];
  const runner = new AiBehaviorRunner(controller, asset, {
    taskRegistry: {
      get: (taskId) => () => {
        log.push(taskId);
        return "success";
      },
    },
    world: {
      entityPosition: (id) => (id === "enemy" ? [0, 0, 0] : targetPosition),
    },
  });
  const tick = (t: number) => runner.tick({ deltaSeconds: 0.1, elapsedSeconds: t, frame: 1 });

  // No perception yet -> attack decorator fails, falls through to idle.
  assert.equal(tick(0.1), "success");
  assert.equal(log.at(-1), "test.idle");
  assert.equal(runner.getDebugSnapshot().failedDecorator, "perception:sight");

  // Sight stimulus present but target is far -> distance decorator fails.
  controller.setPerception([
    { sense: "sight", sourceEntityId: "player", position: targetPosition, distance: 10, strength: 0.9, lineOfSight: true },
  ]);
  assert.equal(tick(0.2), "success");
  assert.equal(log.at(-1), "test.idle");
  assert.equal(runner.getDebugSnapshot().failedDecorator, "distance:target:lte");

  // Bring target into range -> all decorators pass, attack runs and arms cooldown.
  targetPosition = [1, 0, 0];
  controller.setPerception([
    { sense: "sight", sourceEntityId: "player", position: targetPosition, distance: 1, strength: 0.9, lineOfSight: true },
  ]);
  assert.equal(tick(0.3), "success");
  assert.equal(log.at(-1), "test.attack");

  // Within the 1s cooldown window the branch is blocked even though sight/distance hold.
  assert.equal(tick(0.9), "success");
  assert.equal(log.at(-1), "test.idle");
  assert.equal(runner.getDebugSnapshot().failedDecorator, "cooldown:1");

  // After the cooldown elapses the attack branch fires again.
  assert.equal(tick(1.5), "success");
  assert.equal(log.at(-1), "test.attack");
});

check("AiStateTreeRunner drives a patrol -> alert -> chase -> search -> patrol flow", () => {
  const bb = new Blackboard([
    { key: "heardNoise", kind: "boolean", default: false },
    { key: "seesTarget", kind: "boolean", default: false },
  ]);
  const controller = new AIController("ai:guard", "guard", bb);
  const asset = normalizeAiStateTreeAsset({
    schema: 1,
    type: "stateTree",
    states: [
      {
        id: "Patrol",
        tasks: [{ task: "test.patrol" }],
        transitions: [{ to: "Alert", conditions: [{ kind: "blackboard", key: "heardNoise", op: "equals", value: true }] }],
      },
      {
        id: "Alert",
        tasks: [{ task: "test.alert" }],
        transitions: [
          { to: "Chase", conditions: [{ kind: "blackboard", key: "seesTarget", op: "equals", value: true }] },
          { to: "Search", event: "alert-timeout" },
        ],
      },
      {
        id: "Chase",
        tasks: [{ task: "test.chase" }],
        transitions: [{ to: "Search", conditions: [{ kind: "blackboard", key: "seesTarget", op: "equals", value: false }] }],
      },
      {
        id: "Search",
        tasks: [{ task: "test.search" }],
        transitions: [{ to: "Patrol", event: "search-done" }],
      },
    ],
  });
  const log: string[] = [];
  const runner = new AiStateTreeRunner(controller, asset, {
    taskRegistry: {
      get: (taskId) => (context) => {
        log.push(taskId);
        return context.params.hold === true ? "running" : "success";
      },
    },
  });
  const tick = (t: number) => runner.tick({ deltaSeconds: 0.1, elapsedSeconds: t, frame: 1 });

  tick(0.1);
  assert.deepEqual(runner.getDebugSnapshot().activePath, ["Patrol"]);
  assert.equal(controller.goal, "Patrol");
  assert.equal(log.at(-1), "test.patrol");
  assert.deepEqual(runner.getDebugSnapshot().lastTransition, { from: null, to: "Patrol", reason: "initial" });

  bb.set("heardNoise", true);
  tick(0.2);
  assert.deepEqual(runner.getDebugSnapshot().activePath, ["Alert"]);
  assert.equal(log.at(-1), "test.alert");
  assert.deepEqual(runner.getDebugSnapshot().lastTransition, { from: "Patrol", to: "Alert", reason: "conditions" });

  bb.set("seesTarget", true);
  tick(0.3);
  assert.deepEqual(runner.getDebugSnapshot().activePath, ["Chase"]);
  assert.equal(log.at(-1), "test.chase");

  bb.set("seesTarget", false);
  tick(0.4);
  assert.deepEqual(runner.getDebugSnapshot().activePath, ["Search"]);
  assert.equal(log.at(-1), "test.search");

  // Search only leaves on the search-done event, not on conditions.
  tick(0.5);
  assert.deepEqual(runner.getDebugSnapshot().activePath, ["Search"]);
  runner.postEvent("search-done");
  tick(0.6);
  assert.deepEqual(runner.getDebugSnapshot().activePath, ["Patrol"]);
  assert.equal(runner.getDebugSnapshot().lastTransition?.reason, "event:search-done");
});

check("AiStateTreeRunner selects nested child states, runs evaluators, and shares the task registry", () => {
  const buildAsset = () =>
    normalizeAiStateTreeAsset({
      schema: 1,
      type: "stateTree",
      evaluators: [{ service: "test.eval", interval: 0.05 }],
      states: [
        {
          id: "Combat",
          enter: [{ kind: "blackboard", key: "inCombat", op: "equals", value: true }],
          tasks: [{ task: "test.face" }],
          states: [
            { id: "Melee", enter: [{ kind: "blackboard", key: "range", op: "equals", value: "near" }], tasks: [{ task: "test.melee" }] },
            { id: "Ranged", tasks: [{ task: "test.shoot" }] },
          ],
        },
        { id: "Idle", tasks: [{ task: "test.idle" }] },
      ],
    });
  const makeRunner = (bb: Blackboard, log: string[]) => {
    const controller = new AIController("ai:npc", "npc", bb);
    return new AiStateTreeRunner(controller, buildAsset(), {
      taskRegistry: { get: (taskId) => () => (log.push(taskId), "success") },
      serviceRegistry: {
        get: (serviceId) =>
          serviceId === "test.eval"
            ? (context) => context.blackboard.set("evaluated", true)
            : undefined,
      },
    });
  };

  // inCombat + near -> Combat > Melee; both active states run their tasks root-first.
  const meleeBb = new Blackboard([
    { key: "inCombat", kind: "boolean", default: false },
    { key: "range", kind: "string", default: "far" },
    { key: "evaluated", kind: "boolean", default: false },
  ]);
  meleeBb.set("inCombat", true);
  meleeBb.set("range", "near");
  const meleeLog: string[] = [];
  const meleeRunner = makeRunner(meleeBb, meleeLog);
  meleeRunner.tick({ deltaSeconds: 0.1, elapsedSeconds: 0.1, frame: 1 });
  assert.deepEqual(meleeRunner.getDebugSnapshot().activePath, ["Combat", "Melee"]);
  assert.deepEqual(meleeLog, ["test.face", "test.melee"]);
  assert.equal(meleeBb.getBoolean("evaluated"), true); // evaluator ran

  // inCombat but not near -> descends into the fallback Ranged child.
  const rangedBb = new Blackboard([
    { key: "inCombat", kind: "boolean", default: false },
    { key: "range", kind: "string", default: "far" },
    { key: "evaluated", kind: "boolean", default: false },
  ]);
  rangedBb.set("inCombat", true);
  const rangedLog: string[] = [];
  const rangedRunner = makeRunner(rangedBb, rangedLog);
  rangedRunner.tick({ deltaSeconds: 0.1, elapsedSeconds: 0.1, frame: 1 });
  assert.deepEqual(rangedRunner.getDebugSnapshot().activePath, ["Combat", "Ranged"]);
  assert.deepEqual(rangedLog, ["test.face", "test.shoot"]);

  // Combat.enter fails -> the Idle sibling is selected instead.
  const idleBb = new Blackboard([
    { key: "inCombat", kind: "boolean", default: false },
    { key: "range", kind: "string", default: "far" },
    { key: "evaluated", kind: "boolean", default: false },
  ]);
  const idleLog: string[] = [];
  const idleRunner = makeRunner(idleBb, idleLog);
  idleRunner.tick({ deltaSeconds: 0.1, elapsedSeconds: 0.1, frame: 1 });
  assert.deepEqual(idleRunner.getDebugSnapshot().activePath, ["Idle"]);
  assert.deepEqual(idleLog, ["test.idle"]);
});

check("AiStateTreeRunner merges StateTree parameters and context into tasks and evaluators", () => {
  const controller = new AIController("ai:boss", "boss", new Blackboard([
    { key: "phase", kind: "string", default: "" },
    { key: "role", kind: "string", default: "" },
  ]));
  const asset = normalizeAiStateTreeAsset({
    schema: 1,
    type: "stateTree",
    parameters: { phase: "intro", speed: 2 },
    context: { role: "boss", arena: "forge" },
    evaluators: [{ service: "test.eval", interval: 0.05, params: { phase: "service" } }],
    states: [
      {
        id: "Intro",
        tasks: [{ task: "test.record", params: { speed: 6 } }],
      },
    ],
  });
  const seen: Record<string, unknown>[] = [];
  const runner = new AiStateTreeRunner(controller, asset, {
    taskRegistry: {
      get: (taskId) =>
        taskId === "test.record"
          ? (context) => {
              seen.push(context.params);
              context.blackboard.set("phase", String(context.params.phase ?? ""));
              const authoredContext = context.params.context;
              if (authoredContext && typeof authoredContext === "object" && !Array.isArray(authoredContext)) {
                context.blackboard.set("role", String((authoredContext as Record<string, unknown>).role ?? ""));
              }
              return "success";
            }
          : undefined,
    },
    serviceRegistry: {
      get: (serviceId) =>
        serviceId === "test.eval"
          ? (context) => {
              seen.push(context.params);
            }
          : undefined,
    },
  });

  runner.tick({ deltaSeconds: 0.1, elapsedSeconds: 0.1, frame: 1 });
  assert.equal(seen.length, 2);
  assert.deepEqual(seen[0], { phase: "service", speed: 2, context: { role: "boss", arena: "forge" } });
  assert.deepEqual(seen[1], { phase: "intro", speed: 6, context: { role: "boss", arena: "forge" } });
  assert.equal(controller.blackboard.getString("phase"), "intro");
  assert.equal(controller.blackboard.getString("role"), "boss");
});

check("AiBehaviorRunner selector rechecks higher priority branches while a lower branch is running", () => {
  const bb = new Blackboard([
    { key: "hasLineOfSight", kind: "boolean", default: false },
    { key: "mode", kind: "string", default: "idle" },
  ]);
  const controller = new AIController("ai:enemy", "enemy", bb);
  const asset = normalizeAiBehaviorTreeAsset({
    schema: 1,
    type: "behaviorTree",
    root: {
      kind: "selector",
      children: [
        {
          kind: "task",
          task: "test.chase",
          decorators: [{ kind: "blackboard", key: "hasLineOfSight", op: "equals", value: true }],
        },
        {
          kind: "task",
          task: "test.patrol",
        },
      ],
    },
  });
  const tasks: string[] = [];
  const runner = new AiBehaviorRunner(controller, asset, {
    taskRegistry: {
      get: (taskId) => {
        if (taskId === "test.patrol") {
          return (context) => {
            tasks.push("patrol");
            context.blackboard.set("mode", "patrol");
            return "running";
          };
        }
        if (taskId === "test.chase") {
          return (context) => {
            tasks.push("chase");
            context.blackboard.set("mode", "chase");
            return "running";
          };
        }
        return undefined;
      },
    },
  });

  assert.equal(runner.tick({ deltaSeconds: 0.016, elapsedSeconds: 0.016, frame: 1 }), "running");
  assert.equal(bb.getString("mode"), "patrol");
  bb.set("hasLineOfSight", true);
  assert.equal(runner.tick({ deltaSeconds: 0.016, elapsedSeconds: 0.032, frame: 2 }), "running");
  assert.equal(bb.getString("mode"), "chase");
  assert.deepEqual(tasks, ["patrol", "chase"]);
  assert.equal(controller.goal, "test.chase");
});

check("AiBehaviorRunner ticks services on interval and resolves subtree assets", () => {
  const bb = new Blackboard([{ key: "mode", kind: "string", default: "idle" }]);
  const controller = new AIController("ai:worker", "worker", bb);
  const root = normalizeAiBehaviorTreeAsset({
    schema: 1,
    type: "behaviorTree",
    root: {
      kind: "sequence",
      services: [{ service: "test.count", interval: 0.5, params: { key: "mode" } }],
      children: [{ kind: "subtree", behavior: "assets/AI/Sub.behavior.json" }],
    },
  });
  const subtree = normalizeAiBehaviorTreeAsset({
    schema: 1,
    type: "behaviorTree",
    root: { kind: "task", task: "forge.setBlackboard", params: { key: "mode", value: "subtree" } },
  });
  let serviceTicks = 0;
  const runner = new AiBehaviorRunner(controller, root, {
    taskRegistry: createDefaultAiTaskRegistry(),
    serviceRegistry: {
      get: (serviceId) =>
        serviceId === "test.count"
          ? () => {
              serviceTicks += 1;
            }
          : undefined,
    },
    resolveSubtree: (assetPath) =>
      assetPath === "assets/AI/Sub.behavior.json" ? subtree : undefined,
  });

  assert.equal(runner.tick({ deltaSeconds: 0.1, elapsedSeconds: 0.1, frame: 1 }), "success");
  assert.equal(serviceTicks, 1);
  assert.equal(bb.getString("mode"), "subtree");
  runner.tick({ deltaSeconds: 0.1, elapsedSeconds: 0.2, frame: 2 });
  assert.equal(serviceTicks, 1);
  runner.tick({ deltaSeconds: 0.4, elapsedSeconds: 0.6, frame: 3 });
  assert.equal(serviceTicks, 2);
});

check("AiBehaviorRunner default perception service writes sight and hearing to blackboard", () => {
  const bb = new Blackboard([
    { key: "target", kind: "entity", default: null },
    { key: "hasLineOfSight", kind: "boolean", default: false },
    { key: "lastKnownTargetPosition", kind: "vec3", default: null },
    { key: "lastHeardPosition", kind: "vec3", default: null },
    { key: "lastHeardSource", kind: "entity", default: null },
  ]);
  const controller = new AIController("ai:enemy", "enemy", bb);
  controller.setPerception([
    {
      sense: "sight",
      sourceEntityId: "player",
      position: [0, 0, 4],
      distance: 4,
      strength: 0.3,
      lineOfSight: true,
    },
    {
      sense: "hearing",
      sourceEntityId: "noise",
      position: [2, 0, 1],
      distance: 2.2,
      strength: 0.8,
    },
  ]);
  const asset = normalizeAiBehaviorTreeAsset({
    schema: 1,
    type: "behaviorTree",
    root: {
      kind: "sequence",
      services: [
        {
          service: "forge.updatePerceptionBlackboard",
          interval: 0.1,
          params: {
            targetKey: "target",
            hasLineOfSightKey: "hasLineOfSight",
            lastKnownPositionKey: "lastKnownTargetPosition",
            lastHeardPositionKey: "lastHeardPosition",
            lastHeardSourceKey: "lastHeardSource",
          },
        },
      ],
      children: [{ kind: "task", task: "forge.wait", params: { seconds: 0.2 } }],
    },
  });
  const runner = new AiBehaviorRunner(controller, asset, {
    taskRegistry: createDefaultAiTaskRegistry(),
    serviceRegistry: createDefaultAiServiceRegistry(),
  });
  assert.equal(runner.tick({ deltaSeconds: 0.016, elapsedSeconds: 0.016, frame: 1 }), "running");
  assert.equal(bb.getEntity("target"), "player");
  assert.equal(bb.getBoolean("hasLineOfSight"), true);
  assert.deepEqual(bb.getVec3("lastKnownTargetPosition"), [0, 0, 4]);
  assert.deepEqual(bb.getVec3("lastHeardPosition"), [2, 0, 1]);
  assert.equal(bb.getEntity("lastHeardSource"), "noise");

  controller.setPerception([]);
  runner.tick({ deltaSeconds: 0.1, elapsedSeconds: 0.116, frame: 2 });
  assert.equal(bb.getBoolean("hasLineOfSight"), false);
  assert.equal(bb.getEntity("target"), "player", "lost sight does not erase the last target");
});

