check("AiBehaviorRunner Smart Object tasks claim, use, and emit a targeted message", () => {
  const bb = new Blackboard([
    { key: "smartObject", kind: "entity", default: null },
    { key: "smartObjectSlot", kind: "string", default: "" },
  ]);
  const controller = new AIController("ai:worker", "worker", bb);
  const smartObjects = new SmartObjectReservationStore();
  smartObjects.setEntities([
    {
      id: "worker",
      components: { Transform: { position: [0, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] } },
    },
    {
      id: "bench",
      components: {
        Transform: { position: [2, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
        [SMART_OBJECT_COMPONENT]: {
          tags: ["workbench"],
          slots: [{ id: "slot-a", tags: ["workbench"] }],
        },
      },
    },
  ]);
  const asset = normalizeAiBehaviorTreeAsset({
    schema: 1,
    type: "behaviorTree",
    root: {
      kind: "sequence",
      children: [
        {
          kind: "task",
          task: "forge.runQueryToBlackboard",
          params: {
            query: "assets/AI/BestWorkbench.query.json",
            resultKey: "smartObject",
            slotResultKey: "smartObjectSlot",
          },
        },
        { kind: "task", task: "forge.claimSmartObject", params: { entityKey: "smartObject", slotKey: "smartObjectSlot" } },
        {
          kind: "task",
          task: "forge.useSmartObject",
          params: {
            entityKey: "smartObject",
            slotKey: "smartObjectSlot",
            messageType: "workbench.use",
            payload: { action: "craft" },
          },
        },
      ],
    },
  });
  const messages: Array<{ type: string; source: string; target?: string; payload?: Record<string, unknown> }> = [];
  const runner = new AiBehaviorRunner(controller, asset, {
    taskRegistry: createDefaultAiTaskRegistry(),
    smartObjects,
    emitMessage: (message) => messages.push(message),
    runQuery: () => ({
      status: "success",
      candidates: [],
      winner: {
        id: "smart-object:bench:slot-a",
        kind: "entity",
        entityId: "bench",
        smartObjectSlotId: "slot-a",
        position: [2, 0, 0],
        score: 1,
        failedTests: [],
      },
    }),
  });
  assert.equal(runner.tick({ deltaSeconds: 0.016, elapsedSeconds: 1, frame: 1 }), "success");
  assert.equal(bb.getEntity("smartObject"), "bench");
  assert.equal(bb.getString("smartObjectSlot"), "slot-a");
  assert.equal(smartObjects.reservation("bench", "slot-a")?.state, "inUse");
  assert.equal(smartObjects.reservation("bench", "slot-a")?.reservedBy, "worker");
  assert.equal(messages[0]?.type, "workbench.use");
  assert.equal(messages[0]?.source, "worker");
  assert.equal(messages[0]?.target, "bench");
  assert.deepEqual(messages[0]?.payload, {
    action: "craft",
    smartObject: "bench",
    reservedBy: "worker",
    slotId: "slot-a",
  });
});

check("AiBehaviorRunner refreshQueryBlackboard service keeps the winner fresh and clears on none", () => {
  const bb = new Blackboard([{ key: "bestCover", kind: "entity", default: null }]);
  const controller = new AIController("ai:enemy", "enemy", bb);
  const asset = normalizeAiBehaviorTreeAsset({
    schema: 1,
    type: "behaviorTree",
    root: {
      kind: "sequence",
      services: [
        {
          service: "forge.refreshQueryBlackboard",
          interval: 0.5,
          params: { query: "assets/AI/BestCover.query.json", resultKey: "bestCover" },
        },
      ],
      children: [{ kind: "task", task: "test.hold" }],
    },
  });
  let winnerEntity: string | null = "cover-a";
  const runner = new AiBehaviorRunner(controller, asset, {
    taskRegistry: { get: () => () => "running" },
    serviceRegistry: createDefaultAiServiceRegistry(),
    runQuery: () => ({
      status: winnerEntity ? "success" : "failure",
      candidates: [],
      winner: winnerEntity
        ? { id: `entity:${winnerEntity}`, kind: "entity", entityId: winnerEntity, position: [1, 0, 0], score: 1, failedTests: [] }
        : null,
    }),
  });

  // First tick runs the service immediately and writes the winner.
  assert.equal(runner.tick({ deltaSeconds: 0.016, elapsedSeconds: 0.016, frame: 1 }), "running");
  assert.equal(bb.getEntity("bestCover"), "cover-a");

  // Winner disappears; once the interval elapses the key is cleared to null.
  winnerEntity = null;
  runner.tick({ deltaSeconds: 0.2, elapsedSeconds: 0.216, frame: 2 }); // within interval, service skipped
  assert.equal(bb.getEntity("bestCover"), "cover-a");
  runner.tick({ deltaSeconds: 0.5, elapsedSeconds: 0.716, frame: 3 }); // interval elapsed, service runs
  assert.equal(bb.getEntity("bestCover"), null);
});

check("AiBehaviorRunner runQueryToBlackboard throttles repeated query runs", () => {
  const bb = new Blackboard([{ key: "bestCover", kind: "entity", default: null }]);
  const controller = new AIController("ai:enemy", "enemy", bb);
  const asset = normalizeAiBehaviorTreeAsset({
    schema: 1,
    type: "behaviorTree",
    root: {
      kind: "task",
      task: "forge.runQueryToBlackboard",
      params: { query: "assets/AI/BestCover.query.json", resultKey: "bestCover", interval: 0.5 },
    },
  });
  let runs = 0;
  const runner = new AiBehaviorRunner(controller, asset, {
    taskRegistry: createDefaultAiTaskRegistry(),
    runQuery: () => {
      runs += 1;
      const entityId = runs === 1 ? "cover-a" : "cover-b";
      return {
        status: "success",
        candidates: [],
        winner: {
          id: `entity:${entityId}`,
          kind: "entity",
          entityId,
          position: [runs, 0, 0],
          score: 1,
          failedTests: [],
        },
      };
    },
  });
  assert.equal(runner.tick({ deltaSeconds: 0.016, elapsedSeconds: 0.016, frame: 1 }), "success");
  assert.equal(bb.getEntity("bestCover"), "cover-a");
  assert.equal(runs, 1);
  assert.equal(runner.tick({ deltaSeconds: 0.1, elapsedSeconds: 0.116, frame: 2 }), "success");
  assert.equal(bb.getEntity("bestCover"), "cover-a");
  assert.equal(runs, 1);
  assert.equal(runner.tick({ deltaSeconds: 0.4, elapsedSeconds: 0.516, frame: 3 }), "success");
  assert.equal(bb.getEntity("bestCover"), "cover-b");
  assert.equal(runs, 2);
});

