check("AISubsystem bridges script damage messages into gameplay perception blackboard keys", () => {
  const ai = new AISubsystem();
  ai.setAssetLibrary({
    blackboards: new Map([
      [
        "assets/AI/Stimulus.blackboard.json",
        normalizeAiBlackboardAsset({
          schema: 1,
          type: "blackboard",
          keys: [
            { key: "lastStimulusPosition", kind: "vec3", default: null },
            { key: "lastStimulusSource", kind: "entity", default: null },
            { key: "lastStimulusSense", kind: "string", default: "" },
            { key: "lastStimulusEvent", kind: "string", default: "" },
          ],
        }),
      ],
    ]),
    behaviors: new Map([
      [
        "assets/AI/Stimulus.behavior.json",
        normalizeAiBehaviorTreeAsset({
          schema: 1,
          type: "behaviorTree",
          blackboard: "assets/AI/Stimulus.blackboard.json",
          root: {
            kind: "sequence",
            services: [
              {
                service: "forge.updatePerceptionBlackboard",
                interval: 0.01,
                params: {
                  lastStimulusPositionKey: "lastStimulusPosition",
                  lastStimulusSourceKey: "lastStimulusSource",
                  lastStimulusSenseKey: "lastStimulusSense",
                  lastStimulusEventKey: "lastStimulusEvent",
                },
              },
            ],
            children: [{ kind: "task", task: "forge.wait", params: { seconds: 1 } }],
          },
        }),
      ],
    ]),
  });
  ai.setEntities([
    {
      id: "enemy",
      components: {
        Transform: { position: [0, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
        [AI_CONTROLLER_COMPONENT]: {
          behaviorTree: "assets/AI/Stimulus.behavior.json",
          perception: { hearingRadius: 2 },
        },
      },
    },
    {
      id: "player",
      components: {
        Transform: { position: [5, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
      },
    },
  ]);
  const controller = ai.getControllerForPawn("enemy");
  assert.ok(controller);
  assert.equal(
    ai.emitScriptStimulus({
      type: "Damage.Apply",
      source: "player",
      target: "enemy",
      payload: { position: [5, 0, 0], amount: 20 },
    }),
    true,
  );
  ai.update({ deltaSeconds: 0.016, elapsedSeconds: 0.016, frame: 1 });
  const stimulus = ai.getDebugSnapshot().controllers[0]?.perception?.[0];
  assert.equal(stimulus?.sense, "damage");
  assert.equal(stimulus?.sourceEntityId, "player");
  assert.equal(stimulus?.eventType, "Damage.Apply");
  assert.deepEqual(controller?.blackboard.getVec3("lastStimulusPosition"), [5, 0, 0]);
  assert.equal(controller?.blackboard.getEntity("lastStimulusSource"), "player");
  assert.equal(controller?.blackboard.getString("lastStimulusSense"), "damage");
  assert.equal(controller?.blackboard.getString("lastStimulusEvent"), "Damage.Apply");

  ai.update({ deltaSeconds: 0.016, elapsedSeconds: 0.032, frame: 2 });
  assert.equal(ai.getDebugSnapshot().controllers[0]?.perception?.length, 0, "script stimulus is transient");
});

check("AISubsystem sight target-lost grace keeps last target briefly without line of sight", () => {
  let blockers: Array<{ min: [number, number, number]; max: [number, number, number] }> = [];
  const ai = new AISubsystem({ blockers: () => blockers });
  ai.setAssetLibrary({
    blackboards: new Map([
      [
        "assets/AI/Sight.blackboard.json",
        normalizeAiBlackboardAsset({
          schema: 1,
          type: "blackboard",
          keys: [
            { key: "target", kind: "entity", default: null },
            { key: "hasLineOfSight", kind: "boolean", default: false },
            { key: "lastKnownTargetPosition", kind: "vec3", default: null },
          ],
        }),
      ],
    ]),
    behaviors: new Map([
      [
        "assets/AI/Sight.behavior.json",
        normalizeAiBehaviorTreeAsset({
          schema: 1,
          type: "behaviorTree",
          blackboard: "assets/AI/Sight.blackboard.json",
          root: {
            kind: "sequence",
            services: [
              {
                service: "forge.updatePerceptionBlackboard",
                interval: 0.01,
                params: {
                  targetKey: "target",
                  hasLineOfSightKey: "hasLineOfSight",
                  lastKnownPositionKey: "lastKnownTargetPosition",
                },
              },
            ],
            children: [{ kind: "task", task: "forge.wait", params: { seconds: 1 } }],
          },
        }),
      ],
    ]),
  });
  ai.setEntities([
    {
      id: "enemy",
      components: {
        Transform: { position: [0, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
        [AI_CONTROLLER_COMPONENT]: {
          behaviorTree: "assets/AI/Sight.behavior.json",
          perception: { sightRadius: 6, fieldOfViewDeg: 90, targetLostGraceSeconds: 0.1 },
        },
      },
    },
    {
      id: "player",
      components: {
        Transform: { position: [0, 0, 4], rotation: [0, 0, 0], scale: [1, 1, 1] },
      },
    },
  ]);
  const controller = ai.getControllerForPawn("enemy");
  assert.ok(controller);
  ai.update({ deltaSeconds: 0.016, elapsedSeconds: 0.016, frame: 1 });
  assert.equal(controller?.blackboard.getEntity("target"), "player");
  assert.equal(controller?.blackboard.getBoolean("hasLineOfSight"), true);
  assert.equal(ai.getDebugSnapshot().controllers[0]?.perception?.[0]?.lineOfSight, true);

  blockers = [{ min: [-1, -1, 2], max: [1, 2, 2.2] }];
  ai.update({ deltaSeconds: 0.016, elapsedSeconds: 0.032, frame: 2 });
  assert.equal(controller?.blackboard.getEntity("target"), "player");
  assert.equal(controller?.blackboard.getBoolean("hasLineOfSight"), false);
  assert.deepEqual(controller?.blackboard.getVec3("lastKnownTargetPosition"), [0, 0, 4]);
  assert.equal(ai.getDebugSnapshot().controllers[0]?.perception?.[0]?.lineOfSight, false);

  ai.update({ deltaSeconds: 0.2, elapsedSeconds: 0.232, frame: 3 });
  assert.equal(ai.getDebugSnapshot().controllers[0]?.perception?.length, 0);
});

check("AISubsystem resolves blackboard and behavior assets, ticks runner, and emits messages", () => {
  const messages: Array<{ type: string; source: string; target?: string; payload?: Record<string, unknown> }> = [];
  const ai = new AISubsystem({
    emitMessage: (message) => messages.push(message),
  });
  ai.setAssetLibrary({
    blackboards: new Map([
      [
        "assets/AI/Enemy.blackboard.json",
        normalizeAiBlackboardAsset({
          schema: 1,
          type: "blackboard",
          keys: [{ key: "mood", kind: "string", default: "idle" }],
        }),
      ],
    ]),
    behaviors: new Map([
      [
        "assets/AI/Enemy.behavior.json",
        normalizeAiBehaviorTreeAsset({
          schema: 1,
          type: "behaviorTree",
          blackboard: "assets/AI/Enemy.blackboard.json",
          root: {
            kind: "sequence",
            children: [
              { kind: "task", task: "forge.setBlackboard", params: { key: "mood", value: "awake" } },
              { kind: "task", task: "forge.sendMessage", params: { type: "enemy.awake", target: "player" } },
            ],
          },
        }),
      ],
    ]),
  });
  ai.setEntities([
    {
      id: "enemy-asset",
      components: {
        Transform: { position: [0, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
        [AI_CONTROLLER_COMPONENT]: {
          behaviorTree: "assets/AI/Enemy.behavior.json",
        },
      },
    },
  ]);

  const controller = ai.getControllerForPawn("enemy-asset");
  assert.ok(controller);
  assert.equal(controller?.blackboard.keyCount(), 1);
  assert.equal(controller?.blackboard.getString("mood"), "idle");
  ai.update({ deltaSeconds: 0.016, elapsedSeconds: 0.016, frame: 1 });
  assert.equal(controller?.blackboard.getString("mood"), "awake");
  assert.equal(messages[0]?.type, "enemy.awake");
  assert.equal(messages[0]?.source, "enemy-asset");
  assert.equal(messages[0]?.target, "player");
  const behavior = ai.getDebugSnapshot().controllers[0]?.behavior;
  assert.equal(behavior?.lastStatus, "success");
  assert.equal(behavior?.lastTask, "forge.sendMessage");
});

check("AISubsystem Phase 7 cadence slows only far decision and perception ticks", () => {
  const messages: string[] = [];
  let focus: [number, number, number] = [100, 0, 0];
  const ai = new AISubsystem({
    qualityFocusPosition: () => focus,
    emitMessage: (message) => messages.push(message.type),
  });
  ai.setAssetLibrary({
    behaviors: new Map([
      [
        "assets/AI/Far.behavior.json",
        normalizeAiBehaviorTreeAsset({
          schema: 1,
          type: "behaviorTree",
          root: { kind: "task", task: "forge.sendMessage", params: { type: "far.tick" } },
        }),
      ],
    ]),
  });
  ai.setEntities([
    {
      id: "far-enemy",
      components: {
        Transform: { position: [0, 0, 0], rotation: [0, 0, 0], scale: [1, 1, 1] },
        [AI_CONTROLLER_COMPONENT]: { behaviorTree: "assets/AI/Far.behavior.json" },
      },
    },
  ]);
  ai.setDistanceUpdateSettings({ farUpdateHz: 10, farDistance: 30 });
  ai.update({ deltaSeconds: 0.04, elapsedSeconds: 0.04, frame: 1 });
  ai.update({ deltaSeconds: 0.04, elapsedSeconds: 0.08, frame: 2 });
  assert.deepEqual(messages, []);
  ai.update({ deltaSeconds: 0.03, elapsedSeconds: 0.11, frame: 3 });
  assert.deepEqual(messages, ["far.tick"]);

  // Once the NPC returns to the focus area it immediately resumes normal ticks.
  focus = [0, 0, 0];
  ai.update({ deltaSeconds: 0.02, elapsedSeconds: 0.13, frame: 4 });
  assert.deepEqual(messages, ["far.tick", "far.tick"]);
});

