check("RTS resource reservations are atomic and refund at most once", () => {
  const wallet = new ResourceWallet({ food: 200, wood: 200 });
  const barracks = wallet.reserve({ wood: 160 });
  assert.ok(barracks);
  assert.equal(wallet.amount("wood"), 40);
  assert.equal(wallet.reserve({ wood: 80 }), null, "failed reservation cannot partially deduct");
  assert.equal(wallet.amount("wood"), 40);
  assert.equal(wallet.refund(barracks), true);
  assert.equal(wallet.amount("wood"), 200);
  assert.equal(wallet.refund(barracks), false, "the same site cannot refund twice");
  assert.equal(wallet.amount("wood"), 200);
});

check("RTS melee attacks apply JSON damage on cooldown and clear a depleted target", () => {
  const units = new UnitSystem();
  const attacker = units.spawn("player", 0, 0, RTS_TEST_UNIT_STATS);
  const defender = units.spawn("enemy", 1.1, 0, RTS_TEST_UNIT_STATS);
  attacker.setAttackTarget(defender);

  updateUnitCombat([attacker], 0);
  assert.equal(defender.health.current, 88, "first ready hit lands immediately");
  updateUnitCombat([attacker], 0.7);
  assert.equal(defender.health.current, 88, "cooldown prevents an early second hit");
  updateUnitCombat([attacker], 0.7);
  assert.equal(defender.health.current, 76, "second hit lands after the cooldown");

  defender.health.damage(100);
  updateUnitCombat([attacker], 0);
  assert.equal(attacker.attackTarget, null, "stale depleted target is cleared");
  assert.equal(defender.targeted, false, "target marker clears with the attack order");
});

check("RTS melee attacks can damage an enemy command center", () => {
  const units = new UnitSystem();
  const centers = new CommandCenterSystem();
  const attacker = units.spawn("player", 0, 0, RTS_TEST_UNIT_STATS);
  const enemyCenter = centers.spawn("enemy", 1.1, 0, 300);
  attacker.setAttackTarget(enemyCenter);

  const hits: Array<{ damage: number; targetOwner: string }> = [];
  updateUnitCombat([attacker], 0, (hit) => {
    hits.push({ damage: hit.change.applied, targetOwner: hit.target.owner });
  });
  assert.equal(enemyCenter.health.current, 288);
  assert.deepEqual(hits, [{ damage: 12, targetOwner: "enemy" }]);
});

check("RTS match enters victory when the enemy command center is depleted", () => {
  const centers = new CommandCenterSystem();
  centers.spawn("player", 0, 16, 300);
  const enemy = centers.spawn("enemy", 0, -26, 300);
  const match = new RtsMatchState();

  assert.equal(match.update(centers), "active");
  enemy.health.damage(300);
  assert.equal(match.update(centers), "victory");
  assert.equal(match.active, false);
  match.reset();
  assert.equal(match.outcome, "active", "restart returns the match state to playable");
  centers.clear();
  assert.equal(centers.all().length, 0, "restart can discard old command centers");
});

check("RTS death deselects, clears attackers, then removes the defeated unit", () => {
  const units = new UnitSystem();
  const player = units.spawn("player", 0, 0, RTS_TEST_UNIT_STATS);
  const enemy = units.spawn("enemy", 1, 0, RTS_TEST_UNIT_STATS);
  const body = player.object.children[0]!;
  const removed: Unit[] = [];
  const selection = {
    remove: (unit: Unit) => {
      removed.push(unit);
      unit.setSelected(false);
    },
  };
  player.setSelected(true);
  enemy.setAttackTarget(player);
  player.health.damage(100);

  updateUnitDeaths(units, selection, 0.1);
  assert.deepEqual(removed, [player], "a dead selected unit leaves the selection immediately");
  assert.equal(player.selected, false);
  assert.equal(enemy.attackTarget, null, "attackers drop a defeated target immediately");
  assert.ok(units.all().includes(player), "brief defeat pose happens before removal");

  updateUnitDeaths(units, selection, 0.25);
  assert.ok(!units.all().includes(player), "defeated unit leaves the live registry");
  assert.equal(units.unitForObject(body), null, "defeated body no longer resolves from raycasts");
});

check("RTS grid navigation routes a unit around a static blocker", () => {
  const navigation = new RtsNavigation();
  navigation.setBlockers([{ min: [-1, -1, -1], max: [1, 3, 1] }]);
  const path = navigation.plan(new Vector3(-5, 0, 0), new Vector3(5, 0, 0));
  assert.ok(path && path.length > 2, "path detours instead of crossing the blocker");
  assert.ok(path.some((point) => Math.abs(point.z) > 1.5), "path leaves the blocked corridor");

  const units = new UnitSystem();
  const walker = units.spawn("player", -5, 0, RTS_TEST_UNIT_STATS);
  walker.setMovePath(path);
  for (let i = 0; i < 300; i += 1) updateUnitMovement([walker], 1 / 60);
  assert.ok(walker.position.distanceTo(new Vector3(5, 0, 0)) < 0.16, "follows every waypoint to goal");
  assert.equal(walker.pathTarget, null, "clears the path after reaching the goal");
});

check("RTS Faz 2 blockout keeps both flanks reachable around the central ridge", () => {
  const navigation = new RtsNavigation();
  navigation.setBlockers(RTS_BLOCKOUT_MAP.navigationBlockers);
  const start = new Vector3(RTS_BLOCKOUT_MAP.playerStart.x, 0, RTS_BLOCKOUT_MAP.playerStart.z);
  const goal = new Vector3(RTS_BLOCKOUT_MAP.enemyStart.x, 0, RTS_BLOCKOUT_MAP.enemyStart.z);
  const path = navigation.plan(start, goal);
  assert.ok(path && path.length > 2, "the opposing start areas remain connected");
  const detours = path.filter((point) => Math.abs(point.x) > 12.5);
  assert.ok(detours.length > 0, "the route uses an open flank instead of crossing the ridge");
  assert.ok(
    RTS_BLOCKOUT_MAP.externalResource.x > 12 && RTS_BLOCKOUT_MAP.externalResource.z > 4,
    "the external-resource landmark is outside the player start and central ridge",
  );
});

check("RTS placement snap rejects occupied footprints and refreshes navigation blockers", () => {
  const buildings = validateBuildingBalance(
    JSON.parse(readFileSync("public/game-data/balance/buildings.json", "utf8")) as unknown,
  );
  const house = buildings.house ?? assert.fail("house definition missing");
  assert.equal(RTS_PLACEMENT_GRID_SIZE, 2);
  const open = validateBuildingPlacement(house, 20.8, 12.9, RTS_BLOCKOUT_MAP.navigationBlockers);
  assert.deepEqual({ x: open.x, z: open.z, valid: open.valid, reason: open.reason }, {
    x: 20,
    z: 12,
    valid: true,
    reason: null,
  });

  const structures = new PlacedStructureSystem();
  const site = structures.place(house, open.x, open.z);
  const overlap = validateBuildingPlacement(house, 20, 12, structures.navigationBlockers());
  assert.equal(overlap.valid, false);
  assert.equal(overlap.reason, "blocked");

  const navigation = new RtsNavigation();
  navigation.setBlockers([...RTS_BLOCKOUT_MAP.navigationBlockers, ...structures.navigationBlockers()]);
  const route = navigation.plan(new Vector3(14, 0, 12), new Vector3(28, 0, 12));
  assert.ok(route && route.length > 2, "a new structure forces a detour rather than breaking navigation");
  assert.ok(route.some((point) => Math.abs(point.z - 12) > 2.5), "route leaves the structure footprint");
  assert.equal(site.object.name, "rts-construction-site-1");
  assert.equal(structures.cancelLatest(), site, "latest unbuilt foundation can be cancelled");
  assert.equal(structures.navigationBlockers().length, 0);
  structures.clear();
});

console.log(`[engine-tests] ${checks} checks passed`);

function minimalGlbJson(json: unknown): Uint8Array {
  const encoder = new TextEncoder();
  const jsonBytes = encoder.encode(JSON.stringify(json));
  const paddedJsonLength = Math.ceil(jsonBytes.byteLength / 4) * 4;
  const bytes = new Uint8Array(12 + 8 + paddedJsonLength);
  const view = new DataView(bytes.buffer);
  view.setUint32(0, 0x46546c67, true);
  view.setUint32(4, 2, true);
  view.setUint32(8, bytes.byteLength, true);
  view.setUint32(12, paddedJsonLength, true);
  view.setUint32(16, 0x4e4f534a, true);
  bytes.set(jsonBytes, 20);
  for (let index = 20 + jsonBytes.byteLength; index < bytes.byteLength; index += 1) {
    bytes[index] = 0x20;
  }
  return bytes;
}

/** Minimal PNG signature + IHDR carrying width/height (for asset-perf tests). */
function pngHeader(width: number, height: number): Uint8Array {
  const bytes = new Uint8Array(24);
  bytes.set([0x89, 0x50, 0x4e, 0x47, 0x0d, 0x0a, 0x1a, 0x0a], 0);
  const view = new DataView(bytes.buffer);
  view.setUint32(8, 13, false); // IHDR chunk length
  bytes.set([0x49, 0x48, 0x44, 0x52], 12); // "IHDR"
  view.setUint32(16, width, false);
  view.setUint32(20, height, false);
  return bytes;
}

/** Minimal JPEG: SOI + a SOF0 frame header carrying width/height. */
function jpegHeader(width: number, height: number): Uint8Array {
  const bytes = new Uint8Array(12);
  bytes[0] = 0xff;
  bytes[1] = 0xd8; // SOI
  bytes[2] = 0xff;
  bytes[3] = 0xc0; // SOF0
  bytes[4] = 0x00;
  bytes[5] = 0x11; // segment length
  bytes[6] = 0x08; // sample precision
  const view = new DataView(bytes.buffer);
  view.setUint16(7, height, false);
  view.setUint16(9, width, false);
  return bytes;
}

/** Minimal RIFF/WEBP VP8X header carrying (width-1)/(height-1) as 24-bit LE. */
function webpVp8xHeader(width: number, height: number): Uint8Array {
  const bytes = new Uint8Array(30);
  const ascii = (text: string, offset: number): void => {
    for (let i = 0; i < text.length; i += 1) bytes[offset + i] = text.charCodeAt(i);
  };
  ascii("RIFF", 0);
  ascii("WEBP", 8);
  ascii("VP8X", 12);
  const w = width - 1;
  const h = height - 1;
  bytes[24] = w & 0xff;
  bytes[25] = (w >> 8) & 0xff;
  bytes[26] = (w >> 16) & 0xff;
  bytes[27] = h & 0xff;
  bytes[28] = (h >> 8) & 0xff;
  bytes[29] = (h >> 16) & 0xff;
  return bytes;
}
